export const indicators = [
  {
    "id": "londone_open.pine",
    "name": "USDJPY Asian Range Breakout",
    "code": "//@version=5\nindicator(\"USDJPY Asian Range Breakout\", overlay=true, max_boxes_count=100, max_lines_count=100, max_labels_count=100)\n\nasiaStartHour  = input.int(0,     \"Asia Start (UTC Hour)\",  minval=0,   maxval=23)\nasiaEndHour    = input.int(6,     \"Asia End   (UTC Hour)\",  minval=0,   maxval=23)\nbreakoutBuffer = input.float(3.0, \"Breakout Buffer (pips)\", minval=0.0, step=0.5)\nrrRatio        = input.float(2.0, \"Risk:Reward Ratio\",      minval=1.0, step=0.5)\nstopBuffer     = input.float(5.0, \"Stop Buffer (pips)\",     minval=0.0, step=0.5)\nrrBoxWidth     = input.int(30,    \"RR Box Width (bars)\",    minval=5, maxval=200, step=5)\nshowAsiaBox    = input.bool(true,  \"Show Asia Range Box\")\nshowLabels     = input.bool(true,  \"Show Labels\")\n\npipSize = syminfo.mintick * 10\n\nvar float asiaHigh     = na\nvar float asiaLow      = na\nvar int   asiaStartBar = na\nvar int   asiaEndBar   = na\nvar bool  asiaLocked   = false\nvar bool  longFired    = false\nvar bool  shortFired   = false\nvar box   asiaBox      = na\n\nbarHourUTC() => hour(time, \"UTC\")\nbarMinUTC()  => minute(time, \"UTC\")\n\nisAsiaHour() =>\n    h = barHourUTC()\n    h >= asiaStartHour and h < asiaEndHour\n\nisLondonHour() =>\n    h = barHourUTC()\n    h >= 7 and h < 16\n\nisWeekday() =>\n    d = dayofweek(time, \"UTC\")\n    d >= 2 and d <= 6\n\nnewAsiaSession = barHourUTC() == asiaStartHour and barMinUTC() == 0 and isWeekday()\n\nif newAsiaSession\n    asiaHigh     := high\n    asiaLow      := low\n    asiaStartBar := bar_index\n    asiaEndBar   := bar_index\n    asiaLocked   := false\n    longFired    := false\n    shortFired   := false\n    asiaBox      := na\n\nif isAsiaHour() and not asiaLocked\n    asiaHigh   := math.max(asiaHigh, high)\n    asiaLow    := math.min(asiaLow,  low)\n    asiaEndBar := bar_index\n\nif barHourUTC() == asiaEndHour and barMinUTC() == 0 and not asiaLocked\n    asiaLocked := true\n\nif showAsiaBox and asiaLocked and not na(asiaHigh) and not na(asiaStartBar)\n    if na(asiaBox)\n        asiaBox := box.new(asiaStartBar, asiaHigh, asiaEndBar, asiaLow, border_color=color.new(color.orange, 0), border_width=2, bgcolor=color.new(color.orange, 88))\n\nbufPips = breakoutBuffer * pipSize\nstopBuf = stopBuffer * pipSize\n\ninWindow    = isLondonHour() and asiaLocked and not na(asiaHigh) and not na(asiaLow)\nlongSignal  = inWindow and not longFired  and close >  asiaHigh + bufPips and close[1] <= asiaHigh + bufPips\nshortSignal = inWindow and not shortFired and close <  asiaLow  - bufPips and close[1] >= asiaLow  - bufPips\n\nif longSignal\n    longFired := true\nif shortSignal\n    shortFired := true\n\nif longSignal\n    ep     = close\n    slDist = math.abs(ep - (asiaLow - stopBuf))\n    sl     = ep - slDist\n    tp     = ep + slDist * rrRatio\n    rw     = bar_index + rrBoxWidth\n    box.new(bar_index, tp,    rw, ep, border_color=color.new(#00E676, 0),  border_width=1, bgcolor=color.new(#00E676, 85))\n    box.new(bar_index, ep,    rw, sl, border_color=color.new(#FF1744, 0),  border_width=1, bgcolor=color.new(#FF1744, 85))\n    line.new(bar_index, ep,   rw, ep, color=color.new(color.white, 15), width=1, style=line.style_solid)\n    if showLabels\n        label.new(rw, tp, \"  TP \" + str.tostring(rrRatio) + \"R  +\" + str.tostring(math.round(tp - ep, 3)), color=color.new(#00E676, 0), textcolor=color.white, style=label.style_label_left, size=size.small)\n        label.new(rw, ep, \"  ENTRY  \" + str.tostring(math.round(ep, 3)), color=color.new(#21262D, 0), textcolor=color.white, style=label.style_label_left, size=size.small)\n        label.new(rw, sl, \"  SL  -\" + str.tostring(math.round(slDist / pipSize, 1)) + \" pips\", color=color.new(#FF1744, 0), textcolor=color.white, style=label.style_label_left, size=size.small)\n    alert(\"USDJPY BUY - Asia High breakout\", alert.freq_once_per_bar)\n\nif shortSignal\n    ep     = close\n    slDist = math.abs(ep - (asiaHigh + stopBuf))\n    sl     = ep + slDist\n    tp     = ep - slDist * rrRatio\n    rw     = bar_index + rrBoxWidth\n    box.new(bar_index, ep,    rw, tp, border_color=color.new(#00E676, 0),  border_width=1, bgcolor=color.new(#00E676, 85))\n    box.new(bar_index, sl,    rw, ep, border_color=color.new(#FF1744, 0),  border_width=1, bgcolor=color.new(#FF1744, 85))\n    line.new(bar_index, ep,   rw, ep, color=color.new(color.white, 15), width=1, style=line.style_solid)\n    if showLabels\n        label.new(rw, sl, \"  SL  +\" + str.tostring(math.round(slDist / pipSize, 1)) + \" pips\", color=color.new(#FF1744, 0), textcolor=color.white, style=label.style_label_left, size=size.small)\n        label.new(rw, ep, \"  ENTRY  \" + str.tostring(math.round(ep, 3)), color=color.new(#21262D, 0), textcolor=color.white, style=label.style_label_left, size=size.small)\n        label.new(rw, tp, \"  TP \" + str.tostring(rrRatio) + \"R  -\" + str.tostring(math.round(slDist / pipSize * rrRatio, 1)) + \" pips\", color=color.new(#00E676, 0), textcolor=color.white, style=label.style_label_left, size=size.small)\n    alert(\"USDJPY SELL - Asia Low breakout\", alert.freq_once_per_bar)\n\nplotshape(longSignal,  title=\"BUY\",  style=shape.triangleup,   location=location.belowbar, color=color.new(#00E676, 0), size=size.normal, text=\"BUY\")\nplotshape(shortSignal, title=\"SELL\", style=shape.triangledown, location=location.abovebar, color=color.new(#FF1744, 0), size=size.normal, text=\"SELL\")\n\nvar table tbl = table.new(position.top_right, 2, 6, border_color=color.new(#42A5F5, 40), border_width=1, bgcolor=color.new(#0D1117, 0))\n\nif barstate.islast\n    table.cell(tbl, 0, 0, \"Asian Breakout\", text_color=color.new(#FF8C00, 0), text_size=size.small, bgcolor=color.new(#FF8C00, 80))\n    table.cell(tbl, 1, 0, \"USDJPY\",         text_color=color.new(#FF8C00, 0), text_size=size.small, bgcolor=color.new(#FF8C00, 80))\n    table.cell(tbl, 0, 1, \"Asia High\",       text_color=color.silver, text_size=size.tiny)\n    table.cell(tbl, 1, 1, na(asiaHigh) ? \"---\" : str.tostring(math.round(asiaHigh, 3)), text_color=color.new(#00E676, 0), text_size=size.tiny)\n    table.cell(tbl, 0, 2, \"Asia Low\",        text_color=color.silver, text_size=size.tiny)\n    table.cell(tbl, 1, 2, na(asiaLow) ? \"---\" : str.tostring(math.round(asiaLow, 3)),   text_color=color.new(#FF1744, 0), text_size=size.tiny)\n    table.cell(tbl, 0, 3, \"Range pips\",      text_color=color.silver, text_size=size.tiny)\n    rangeVal = na(asiaHigh) or na(asiaLow) ? \"---\" : str.tostring(math.round((asiaHigh - asiaLow) / pipSize, 1))\n    table.cell(tbl, 1, 3, rangeVal,          text_color=color.new(#FFA726, 0), text_size=size.tiny)\n    table.cell(tbl, 0, 4, \"RR Ratio\",        text_color=color.silver, text_size=size.tiny)\n    table.cell(tbl, 1, 4, \"1:\" + str.tostring(rrRatio), text_color=color.new(#42A5F5, 0), text_size=size.tiny)\n    table.cell(tbl, 0, 5, \"Session\",         text_color=color.silver, text_size=size.tiny)\n    table.cell(tbl, 1, 5, asiaLocked ? \"London/NY\" : \"Asia\", text_color=color.silver, text_size=size.tiny)"
  },
  {
    "id": "crt.pine",
    "name": "Crt",
    "code": "// ============================================================\n// CRT + TBS Auto Signal [Pro] \u2014 High Probability Edition\n// Candle Range Theory (CRT) + Time-Based Sessions (TBS)\n//                           + 1H HTF Alignment Filter\n// ============================================================\n// SIGNAL LOGIC (all must be TRUE):\n//  \u2705 1. CRT 3-candle pattern on current TF\n//  \u2705 2. Inside TBS kill zone session window\n//  \u2705 3. 1H Higher TimeFrame aligned (3 confluence checks)\n//  \u2705 4. Optional: current TF EMA + Volume confirmation\n//\n// 1H HTF ALIGNMENT \u2014 3 confluence checks:\n//  \u2192 Check 1: Price above/below 1H EMA50\n//  \u2192 Check 2: Price above/below 1H EMA200\n//  \u2192 Check 3: Last 1H candle closed bullish/bearish\n//  Strict mode = all 3 must agree | Relaxed = 2 of 3\n// ============================================================\n\n//@version=5\nindicator(\"CRT + TBS + 1H HTF [High Probability]\",\n     shorttitle = \"CRT+TBS+HTF\",\n     overlay    = true,\n     max_labels_count = 500,\n     max_lines_count  = 500,\n     max_boxes_count  = 500)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// INPUTS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ngrp_htf  = \"\ud83d\udcd0 1H HTF Alignment (High Probability)\"\ngrp_crt  = \"\u2699\ufe0f CRT Settings\"\ngrp_tbs  = \"\u23f0 TBS Session Windows\"\ngrp_sig  = \"\ud83c\udfaf Signal & RR Settings\"\ngrp_filt = \"\ud83d\udd0d Additional Filters\"\ngrp_col  = \"\ud83c\udfa8 Colors\"\n\n// HTF\nuse_htf_filter  = input.bool(true,  \"Enable 1H HTF Alignment Filter\", group=grp_htf)\nhtf_tf          = input.timeframe(\"60\", \"HTF Timeframe\", group=grp_htf)\nhtf_ema_fast    = input.int(50,  \"1H EMA Fast (trend bias)\",  minval=5,  group=grp_htf)\nhtf_ema_slow    = input.int(200, \"1H EMA Slow (major trend)\", minval=20, group=grp_htf)\nshow_htf_emas   = input.bool(true, \"Show 1H EMAs on chart\", group=grp_htf)\nhtf_require_all = input.bool(true, \"Require ALL 3 HTF checks (strict mode)\", group=grp_htf,\n     tooltip = \"ON = all 3 checks must align \u2192 fewer but higher quality signals\\nOFF = 2 of 3 checks \u2192 more signals\")\nshow_htf_bias   = input.bool(true, \"Show 1H Bias label on chart\", group=grp_htf)\n\n// CRT\nshow_crt_boxes   = input.bool(true, \"Show CRT Range Boxes\",         group=grp_crt)\nshow_manip_wicks = input.bool(true, \"Show Manipulation Wick Lines\", group=grp_crt)\n\n// TBS \u2014 Session Selector\ntrade_session = input.string(\"London + New York\", \"Trade Only During Session\",\n     options = [\"London\", \"New York\", \"Asia\", \"London + New York\", \"London + Asia\", \"New York + Asia\", \"All Sessions\"],\n     group   = grp_tbs,\n     tooltip = \"Signals only fire inside the selected session window(s).\\nLondon:   02:00-05:00 ET\\nNew York: 08:30-15:00 ET\\nAsia:     20:00-23:00 ET\")\nlondon_start = input.session(\"0200-0500\", \"  London Time Window (ET)\",   group=grp_tbs)\nny_start     = input.session(\"0830-1500\", \"  New York Time Window (ET)\", group=grp_tbs)\nasia_start   = input.session(\"2000-2300\", \"  Asia Time Window (ET)\",     group=grp_tbs)\n\n// Signal & RR\nshow_bull_sig  = input.bool(true,  \"Show Bullish Signals\", group=grp_sig)\nshow_bear_sig  = input.bool(true,  \"Show Bearish Signals\", group=grp_sig)\nsig_label_size = input.string(\"normal\", \"Label Size\", options=[\"tiny\",\"small\",\"normal\",\"large\"], group=grp_sig)\nshow_rr_box    = input.bool(true,  \"Show RR Shape (TradingView Style)\", group=grp_sig)\nrr_ratio       = input.float(2.0,  \"Risk:Reward Ratio\",  minval=1.0, maxval=10.0, step=0.5, group=grp_sig)\natr_mult_sl    = input.float(0.5,  \"SL ATR Multiplier\",  minval=0.1, maxval=3.0,  step=0.1, group=grp_sig)\nrr_box_width   = input.int(25, \"RR Box Width (bars)\", minval=5, maxval=150, step=5, group=grp_sig)\n\n// Extra filters\nuse_ltf_ema    = input.bool(false, \"Current TF EMA Filter\", group=grp_filt)\nltf_ema_len    = input.int(50, \"Current TF EMA Length\", minval=5, group=grp_filt)\nuse_vol_filter = input.bool(false, \"Volume Filter (above MA)\", group=grp_filt)\nvol_len        = input.int(20, \"Volume MA Length\", group=grp_filt)\n\n// Colors\nbull_col     = input.color(color.new(#00E676, 0),  \"Bullish Signal Color\", group=grp_col)\nbear_col     = input.color(color.new(#FF1744, 0),  \"Bearish Signal Color\", group=grp_col)\nbox_col      = input.color(color.new(#FFA726, 15), \"CRT Box Color\",        group=grp_col)\nhtf_bull_col = input.color(color.new(#00BCD4, 40), \"1H EMA Bull Color\",    group=grp_col)\nhtf_bear_col = input.color(color.new(#FF6F00, 40), \"1H EMA Bear Color\",    group=grp_col)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// UTILITY\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nf_label_size(s) =>\n    s == \"tiny\" ? size.tiny : s == \"small\" ? size.small : s == \"large\" ? size.large : size.normal\n\natr14 = ta.atr(14)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// 1H HTF ALIGNMENT \u2014 3 CONFLUENCE CHECKS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n// Pull 1H data (no lookahead to avoid repainting)\nhtf_close = request.security(syminfo.tickerid, htf_tf, close[1], lookahead=barmerge.lookahead_off)\nhtf_open  = request.security(syminfo.tickerid, htf_tf, open[1],  lookahead=barmerge.lookahead_off)\nhtf_ema_f = request.security(syminfo.tickerid, htf_tf, ta.ema(close, htf_ema_fast), lookahead=barmerge.lookahead_off)\nhtf_ema_s = request.security(syminfo.tickerid, htf_tf, ta.ema(close, htf_ema_slow), lookahead=barmerge.lookahead_off)\n\n// Check 1: price vs 1H EMA50\nhtf_c1_bull = close > htf_ema_f\nhtf_c1_bear = close < htf_ema_f\n\n// Check 2: price vs 1H EMA200\nhtf_c2_bull = close > htf_ema_s\nhtf_c2_bear = close < htf_ema_s\n\n// Check 3: last 1H candle structure (closed bull/bear)\nhtf_c3_bull = htf_close > htf_open\nhtf_c3_bear = htf_close < htf_open\n\n// Score (0\u20133)\nhtf_bull_score = (htf_c1_bull ? 1 : 0) + (htf_c2_bull ? 1 : 0) + (htf_c3_bull ? 1 : 0)\nhtf_bear_score = (htf_c1_bear ? 1 : 0) + (htf_c2_bear ? 1 : 0) + (htf_c3_bear ? 1 : 0)\n\nhtf_threshold = htf_require_all ? 3 : 2\n\nhtf_bull_ok = not use_htf_filter or (htf_bull_score >= htf_threshold)\nhtf_bear_ok = not use_htf_filter or (htf_bear_score >= htf_threshold)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// Plot 1H EMAs\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nplot(show_htf_emas ? htf_ema_f : na,\n     title=\"1H EMA50\",\n     color=htf_c1_bull ? htf_bull_col : htf_bear_col,\n     linewidth=2)\n\nplot(show_htf_emas ? htf_ema_s : na,\n     title=\"1H EMA200\",\n     color=htf_c2_bull ? color.new(#00BCD4, 65) : color.new(#FF6F00, 65),\n     linewidth=1)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// 1H Bias floating label\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nhtf_bias_col = htf_bull_score > htf_bear_score ? color.new(#00E676, 0) :\n               htf_bear_score > htf_bull_score ? color.new(#FF1744, 0) :\n               color.new(#FFA726, 0)\n\nvar label htf_label = na\nif show_htf_bias and barstate.islast\n    label.delete(htf_label)\n    htf_label := label.new(bar_index + 2, htf_ema_f,\n         (htf_bull_score > htf_bear_score ? \"1H \u25b2 BULL \" : htf_bear_score > htf_bull_score ? \"1H \u25bc BEAR \" : \"1H \u25c6 MIXED \") +\n         str.tostring(math.max(htf_bull_score, htf_bear_score)) + \"/3\" +\n         \"\\nEMA50:  \" + str.tostring(math.round(htf_ema_f, 2)) +\n         \"\\nEMA200: \" + str.tostring(math.round(htf_ema_s, 2)),\n         color     = color.new(#161B22, 5),\n         textcolor = htf_bias_col,\n         style     = label.style_label_left,\n         size      = size.small)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// CURRENT TF FILTERS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nltf_ema_val = ta.ema(close, ltf_ema_len)\nltf_bull    = not use_ltf_ema or close > ltf_ema_val\nltf_bear    = not use_ltf_ema or close < ltf_ema_val\nvol_ma      = ta.sma(volume, vol_len)\nvol_ok      = not use_vol_filter or volume > vol_ma\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// TBS SESSION DETECTION\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// Detect each session window\nin_london_raw = not na(time(\"\", london_start, \"America/New_York\"))\nin_ny_raw     = not na(time(\"\", ny_start,     \"America/New_York\"))\nin_asia_raw   = not na(time(\"\", asia_start,   \"America/New_York\"))\n\n// Apply session selector \u2014 only enable windows matching the chosen session\nuse_lon = trade_session == \"London\"           or trade_session == \"London + New York\" or\n          trade_session == \"London + Asia\"    or trade_session == \"All Sessions\"\nuse_ny  = trade_session == \"New York\"         or trade_session == \"London + New York\" or\n          trade_session == \"New York + Asia\"  or trade_session == \"All Sessions\"\nuse_asi = trade_session == \"Asia\"             or trade_session == \"London + Asia\"     or\n          trade_session == \"New York + Asia\"  or trade_session == \"All Sessions\"\n\nin_london  = use_lon and in_london_raw\nin_ny      = use_ny  and in_ny_raw\nin_asia    = use_asi and in_asia_raw\nin_session = in_london or in_ny or in_asia\n\n// Session background highlight\nbgcolor(in_london ? color.new(#42A5F5, 93) : na, title=\"London BG\")\nbgcolor(in_ny     ? color.new(#66BB6A, 93) : na, title=\"New York BG\")\nbgcolor(in_asia   ? color.new(#AB47BC, 93) : na, title=\"Asia BG\")\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// CRT PATTERN DETECTION\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nc1_high = high[2]\nc1_low  = low[2]\n\nc2_high  = high[1]\nc2_low   = low[1]\nc2_close = close[1]\nc2_open  = open[1]\n\nc2_sweep_high         = c2_high > c1_high\nc2_sweep_low          = c2_low  < c1_low\nc2_rejected_from_high = c2_sweep_high and c2_close < c1_high\nc2_rejected_from_low  = c2_sweep_low  and c2_close > c1_low\n\nc3_bull_confirm = close > c1_high\nc3_bear_confirm = close < c1_low\n\ncrt_bull = c2_rejected_from_low  and c3_bull_confirm\ncrt_bear = c2_rejected_from_high and c3_bear_confirm\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// FINAL SIGNAL \u2014 ALL LAYERS COMBINED\n//  CRT \u2705  +  TBS \u2705  +  1H HTF \u2705  +  Filters \u2705\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfinal_bull = crt_bull and in_session and htf_bull_ok and ltf_bull and vol_ok and show_bull_sig\nfinal_bear = crt_bear and in_session and htf_bear_ok and ltf_bear and vol_ok and show_bear_sig\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// CRT RANGE BOX\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nif show_crt_boxes and (final_bull or final_bear)\n    box.new(bar_index - 2, c1_high, bar_index, c1_low,\n         border_color=box_col, border_width=1, bgcolor=color.new(box_col, 80))\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// MANIPULATION WICK MARKERS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nif show_manip_wicks and final_bull\n    line.new(bar_index - 1, c2_low, bar_index, c2_low,\n         color=color.new(bull_col, 30), width=2, style=line.style_dotted)\n\nif show_manip_wicks and final_bear\n    line.new(bar_index - 1, c2_high, bar_index, c2_high,\n         color=color.new(bear_col, 30), width=2, style=line.style_dotted)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// RR SHAPE \u2014 TradingView Style\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nif show_rr_box\n    if final_bull\n        entry_p = close\n        sl_p    = low  - (atr14 * atr_mult_sl)\n        tp_p    = entry_p + ((entry_p - sl_p) * rr_ratio)\n        risk    = entry_p - sl_p\n        reward  = tp_p - entry_p\n\n        box.new(bar_index, tp_p, bar_index + rr_box_width, entry_p,\n             border_color=color.new(#00E676, 0), border_width=1, bgcolor=color.new(#00E676, 85))\n        box.new(bar_index, entry_p, bar_index + rr_box_width, sl_p,\n             border_color=color.new(#FF1744, 0), border_width=1, bgcolor=color.new(#FF1744, 85))\n        line.new(bar_index, entry_p, bar_index + rr_box_width, entry_p,\n             color=color.new(color.white, 15), width=1, style=line.style_solid)\n\n        label.new(bar_index + rr_box_width, tp_p,\n             \"  TP  \" + str.tostring(rr_ratio) + \"R  +\" + str.tostring(math.round(reward, 2)),\n             color=color.new(#00E676, 0), textcolor=color.white, style=label.style_label_left, size=size.small)\n        label.new(bar_index + rr_box_width, entry_p,\n             \"  ENTRY  \" + str.tostring(math.round(entry_p, 2)),\n             color=color.new(#21262D, 0), textcolor=color.white, style=label.style_label_left, size=size.small)\n        label.new(bar_index + rr_box_width, sl_p,\n             \"  SL  -\" + str.tostring(math.round(risk, 2)),\n             color=color.new(#FF1744, 0), textcolor=color.white, style=label.style_label_left, size=size.small)\n\n    if final_bear\n        entry_p = close\n        sl_p    = high + (atr14 * atr_mult_sl)\n        tp_p    = entry_p - ((sl_p - entry_p) * rr_ratio)\n        risk    = sl_p - entry_p\n        reward  = entry_p - tp_p\n\n        box.new(bar_index, entry_p, bar_index + rr_box_width, tp_p,\n             border_color=color.new(#00E676, 0), border_width=1, bgcolor=color.new(#00E676, 85))\n        box.new(bar_index, sl_p, bar_index + rr_box_width, entry_p,\n             border_color=color.new(#FF1744, 0), border_width=1, bgcolor=color.new(#FF1744, 85))\n        line.new(bar_index, entry_p, bar_index + rr_box_width, entry_p,\n             color=color.new(color.white, 15), width=1, style=line.style_solid)\n\n        label.new(bar_index + rr_box_width, sl_p,\n             \"  SL  +\" + str.tostring(math.round(risk, 2)),\n             color=color.new(#FF1744, 0), textcolor=color.white, style=label.style_label_left, size=size.small)\n        label.new(bar_index + rr_box_width, entry_p,\n             \"  ENTRY  \" + str.tostring(math.round(entry_p, 2)),\n             color=color.new(#21262D, 0), textcolor=color.white, style=label.style_label_left, size=size.small)\n        label.new(bar_index + rr_box_width, tp_p,\n             \"  TP  \" + str.tostring(rr_ratio) + \"R  -\" + str.tostring(math.round(reward, 2)),\n             color=color.new(#00E676, 0), textcolor=color.white, style=label.style_label_left, size=size.small)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// SIGNAL ARROW LABELS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nlbl_size    = f_label_size(sig_label_size)\nsession_tag = in_london ? \" [LON]\" : in_ny ? \" [NY]\" : in_asia ? \" [ASIA]\" : \"\"\nhtf_score   = htf_bull_score > htf_bear_score ? htf_bull_score : htf_bear_score\n\nif final_bull\n    label.new(bar_index, low - atr14 * 1.5,\n         \"\u25b2 BUY\" + session_tag + \" \u00b7 1H \" + str.tostring(htf_score) + \"/3\\nCRT+TBS+HTF\",\n         color=bull_col, textcolor=color.white, style=label.style_label_up, size=lbl_size)\n\nif final_bear\n    label.new(bar_index, high + atr14 * 1.5,\n         \"\u25bc SELL\" + session_tag + \" \u00b7 1H \" + str.tostring(htf_score) + \"/3\\nCRT+TBS+HTF\",\n         color=bear_col, textcolor=color.white, style=label.style_label_down, size=lbl_size)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// ALERTS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nalertcondition(final_bull,\n     title   = \"CRT+TBS+1H BUY\",\n     message = \"\ud83d\udfe2 HIGH PROB BUY | {{ticker}} | TF: {{interval}} | 1H aligned | Price: {{close}}\")\nalertcondition(final_bear,\n     title   = \"CRT+TBS+1H SELL\",\n     message = \"\ud83d\udd34 HIGH PROB SELL | {{ticker}} | TF: {{interval}} | 1H aligned | Price: {{close}}\")\nalertcondition(final_bull or final_bear,\n     title   = \"CRT+TBS+1H Any Signal\",\n     message = \"\u26a1 HIGH PROB SIGNAL | {{ticker}} | TF: {{interval}} | Price: {{close}}\")\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// DASHBOARD TABLE\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nvar table dash = table.new(position.top_right, 2, 12,\n     bgcolor=#0D1117, border_color=color.new(#42A5F5, 40),\n     border_width=1, frame_color=color.new(#42A5F5, 20), frame_width=2)\n\nif barstate.islast\n    table.cell(dash, 0, 0, \"CRT+TBS+1H HTF\", text_color=#42A5F5, text_size=size.small, bgcolor=#161B22, text_halign=text.align_center)\n    table.cell(dash, 1, 0, \"STATUS\",          text_color=#42A5F5, text_size=size.small, bgcolor=#161B22, text_halign=text.align_center)\n\n    table.cell(dash, 0, 1, \"1H EMA50\",     text_color=color.silver, text_size=size.tiny)\n    table.cell(dash, 1, 1, htf_c1_bull ? \"\u25b2 BULL\" : \"\u25bc BEAR\",\n         text_color=htf_c1_bull ? #00E676 : #FF1744, text_size=size.tiny)\n\n    table.cell(dash, 0, 2, \"1H EMA200\",    text_color=color.silver, text_size=size.tiny)\n    table.cell(dash, 1, 2, htf_c2_bull ? \"\u25b2 BULL\" : \"\u25bc BEAR\",\n         text_color=htf_c2_bull ? #00E676 : #FF1744, text_size=size.tiny)\n\n    table.cell(dash, 0, 3, \"1H Structure\", text_color=color.silver, text_size=size.tiny)\n    table.cell(dash, 1, 3, htf_c3_bull ? \"\u25b2 BULL\" : \"\u25bc BEAR\",\n         text_color=htf_c3_bull ? #00E676 : #FF1744, text_size=size.tiny)\n\n    table.cell(dash, 0, 4, \"1H Bias\",      text_color=color.silver, text_size=size.tiny, bgcolor=#0D1117)\n    table.cell(dash, 1, 4,\n         htf_bull_score >= htf_threshold ? \"\u2705 BULL \" + str.tostring(htf_bull_score) + \"/3\" :\n         htf_bear_score >= htf_threshold ? \"\u2705 BEAR \" + str.tostring(htf_bear_score) + \"/3\" : \"\u26a0 MIXED\",\n         text_color=htf_bull_score >= htf_threshold ? #00E676 : htf_bear_score >= htf_threshold ? #FF1744 : #FFA726,\n         text_size=size.tiny, bgcolor=#0D1117)\n\n    table.cell(dash, 0, 5, \"Session Mode\",  text_color=color.silver, text_size=size.tiny)\n    table.cell(dash, 1, 5, trade_session,   text_color=#FFA726,       text_size=size.tiny)\n\n    table.cell(dash, 0, 6, \"London\",        text_color=color.silver, text_size=size.tiny)\n    table.cell(dash, 1, 6, not use_lon ? \"\u2014 OFF\" : in_london ? \"\ud83d\udfe2 ACTIVE\" : \"\u26ab WAITING\",\n         text_color=in_london ? #00E676 : use_lon ? color.gray : #363A45, text_size=size.tiny)\n\n    table.cell(dash, 0, 7, \"New York\",      text_color=color.silver, text_size=size.tiny)\n    table.cell(dash, 1, 7, not use_ny  ? \"\u2014 OFF\" : in_ny     ? \"\ud83d\udfe2 ACTIVE\" : \"\u26ab WAITING\",\n         text_color=in_ny     ? #00E676 : use_ny  ? color.gray : #363A45, text_size=size.tiny)\n\n    table.cell(dash, 0, 8, \"Asia\",          text_color=color.silver, text_size=size.tiny)\n    table.cell(dash, 1, 8, not use_asi ? \"\u2014 OFF\" : in_asia   ? \"\ud83d\udfe2 ACTIVE\" : \"\u26ab WAITING\",\n         text_color=in_asia   ? #00E676 : use_asi ? color.gray : #363A45, text_size=size.tiny)\n\n    table.cell(dash, 0, 9, \"CRT Setup\",    text_color=color.silver, text_size=size.tiny)\n    table.cell(dash, 1, 10,\n         c2_rejected_from_low ? \"\u2b06 Bull Manip\" : c2_rejected_from_high ? \"\u2b07 Bear Manip\" : \"Scanning...\",\n         text_color=c2_rejected_from_low ? #00E676 : c2_rejected_from_high ? #FF1744 : color.gray,\n         text_size=size.tiny)\n\n    table.cell(dash, 0, 10, \"Session\",      text_color=color.silver, text_size=size.tiny)\n    table.cell(dash, 1, 10,\n         in_london ? \"London\" : in_ny ? \"New York\" : in_asia ? \"Asia\" : \"\u2014 Off \u2014\",\n         text_color=in_session ? #FFA726 : color.gray, text_size=size.tiny)\n\n    table.cell(dash, 0, 11, \"\u25b6 SIGNAL\",    text_color=#42A5F5, text_size=size.tiny, bgcolor=#161B22)\n    table.cell(dash, 1, 11,\n         final_bull ? \"\u25b2 BUY\"  + session_tag :\n         final_bear ? \"\u25bc SELL\" + session_tag : \"\u2014 Waiting \u2014\",\n         text_color=final_bull ? #00E676 : final_bear ? #FF1744 : color.gray,\n         text_size=size.small, bgcolor=#161B22)"
  },
  {
    "id": "crt_scaping.pine",
    "name": "CRT + TBS + 15M HTF [SCALP]",
    "code": "//@version=5\nindicator(\"CRT + TBS + 15M HTF [SCALP]\", shorttitle = \"CRT\u00b7SCALP\", overlay = true, max_labels_count = 500, max_lines_count = 500, max_boxes_count = 500)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// SCALP TIMEFRAME GUARD\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nscalp_tf_ok = timeframe.in_seconds() <= 300\nvar label tf_warn = na\nif barstate.islast and not scalp_tf_ok\n    label.delete(tf_warn)\n    tf_warn := label.new(bar_index, high, \"\u26a0\ufe0f SCALP EDITION \u2014 Designed for 1M\u20135M only.\", color=color.new(#FF6F00, 0), textcolor=color.white, style=label.style_label_down, size=size.normal)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// GROUPS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ngrp_htf  = \"\ud83d\udcd0 15M HTF Alignment\"\ngrp_crt  = \"\u2699\ufe0f CRT Settings\"\ngrp_tbs  = \"\u23f0 Kill Zones\"\ngrp_sig  = \"\ud83c\udfaf Signal & RR\"\ngrp_filt = \"\ud83d\udd0d Filters\"\ngrp_col  = \"\ud83c\udfa8 Colors\"\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// HTF INPUTS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nuse_htf_filter  = input.bool(true,  \"Enable 15M HTF Filter\",          group=grp_htf)\nhtf_tf          = input.timeframe(\"15\", \"HTF Timeframe\",               group=grp_htf)\nhtf_ema_fast    = input.int(9,   \"EMA Fast\",  minval=3,                group=grp_htf)\nhtf_ema_slow    = input.int(21,  \"EMA Slow\",  minval=5,                group=grp_htf)\nshow_htf_emas   = input.bool(true, \"Show 15M EMAs on chart\",           group=grp_htf)\nhtf_require_all = input.bool(false, \"Strict Mode (all 3 checks)\",      group=grp_htf)\nshow_htf_bias   = input.bool(true, \"Show 15M Bias label\",              group=grp_htf)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// CRT INPUTS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nshow_crt_boxes   = input.bool(true, \"Show CRT Range Boxes\",            group=grp_crt)\nshow_manip_wicks = input.bool(true, \"Show Manipulation Wick Lines\",    group=grp_crt)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// SESSION INPUTS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ntrade_session = input.string(\"London Open + NY Open\", \"Kill Zone\", options=[\"London Open\", \"NY Open\", \"NY Midday\", \"Asian\", \"London Open + NY Open\", \"London Open + NY Open + NY Midday\", \"All Kill Zones\"], group=grp_tbs)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// SIGNAL INPUTS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nshow_bull_sig  = input.bool(true,  \"Show Bullish Signals\",             group=grp_sig)\nshow_bear_sig  = input.bool(true,  \"Show Bearish Signals\",             group=grp_sig)\nsig_label_size = input.string(\"small\", \"Label Size\", options=[\"tiny\",\"small\",\"normal\",\"large\"], group=grp_sig)\nshow_rr_box    = input.bool(true,  \"Show RR Box\",                      group=grp_sig)\nrr_ratio       = input.float(1.5,  \"RR Ratio\",   minval=1.0, maxval=5.0, step=0.5, group=grp_sig)\natr_mult_sl    = input.float(0.3,  \"SL ATR Mult\", minval=0.1, maxval=2.0, step=0.1, group=grp_sig)\nrr_box_width   = input.int(15, \"RR Box Width (bars)\", minval=5, maxval=100, step=5,  group=grp_sig)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// FILTER INPUTS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nuse_ltf_ema     = input.bool(true,  \"Current TF EMA Filter\",           group=grp_filt)\nltf_ema_len     = input.int(9,  \"EMA Length\", minval=3,                group=grp_filt)\nuse_vol_filter  = input.bool(true,  \"Volume Filter (above MA)\",        group=grp_filt)\nvol_len         = input.int(20, \"Volume MA Length\",                    group=grp_filt)\nuse_body_filter = input.bool(true,  \"Min Body Filter (no doji)\",       group=grp_filt)\nmin_body_atr    = input.float(0.1, \"Min Body as % ATR\", minval=0.05, maxval=1.0, step=0.05, group=grp_filt)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// COLOR INPUTS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nbull_col     = input.color(color.new(#00E676, 0),  \"Bull Color\",       group=grp_col)\nbear_col     = input.color(color.new(#FF1744, 0),  \"Bear Color\",       group=grp_col)\nbox_col      = input.color(color.new(#FFA726, 15), \"CRT Box Color\",    group=grp_col)\nhtf_bull_col = input.color(color.new(#00BCD4, 40), \"HTF EMA Bull\",     group=grp_col)\nhtf_bear_col = input.color(color.new(#FF6F00, 40), \"HTF EMA Bear\",     group=grp_col)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// UTILITY\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nf_label_size(s) =>\n    s == \"tiny\" ? size.tiny : s == \"small\" ? size.small : s == \"large\" ? size.large : size.normal\n\natr14 = ta.atr(14)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// 15M HTF DATA\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nhtf_close = request.security(syminfo.tickerid, htf_tf, close[1], lookahead=barmerge.lookahead_off)\nhtf_open  = request.security(syminfo.tickerid, htf_tf, open[1],  lookahead=barmerge.lookahead_off)\nhtf_ema_f = request.security(syminfo.tickerid, htf_tf, ta.ema(close, htf_ema_fast), lookahead=barmerge.lookahead_off)\nhtf_ema_s = request.security(syminfo.tickerid, htf_tf, ta.ema(close, htf_ema_slow), lookahead=barmerge.lookahead_off)\n\nhtf_c1_bull = close > htf_ema_f\nhtf_c1_bear = close < htf_ema_f\nhtf_c2_bull = close > htf_ema_s\nhtf_c2_bear = close < htf_ema_s\nhtf_c3_bull = htf_close > htf_open\nhtf_c3_bear = htf_close < htf_open\n\nhtf_bull_score = (htf_c1_bull ? 1 : 0) + (htf_c2_bull ? 1 : 0) + (htf_c3_bull ? 1 : 0)\nhtf_bear_score = (htf_c1_bear ? 1 : 0) + (htf_c2_bear ? 1 : 0) + (htf_c3_bear ? 1 : 0)\n\nhtf_threshold = htf_require_all ? 3 : 2\nhtf_bull_ok   = not use_htf_filter or (htf_bull_score >= htf_threshold)\nhtf_bear_ok   = not use_htf_filter or (htf_bear_score >= htf_threshold)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// PLOT HTF EMAs\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nplot(show_htf_emas ? htf_ema_f : na, \"15M EMA9\", color=htf_c1_bull ? htf_bull_col : htf_bear_col, linewidth=2)\nplot(show_htf_emas ? htf_ema_s : na, \"15M EMA21\", color=htf_c2_bull ? color.new(#00BCD4,65) : color.new(#FF6F00,65), linewidth=1)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// HTF BIAS LABEL\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nhtf_bias_col = htf_bull_score > htf_bear_score ? color.new(#00E676,0) :\n               htf_bear_score > htf_bull_score ? color.new(#FF1744,0) :\n               color.new(#FFA726,0)\n\nvar label htf_label = na\nif show_htf_bias and barstate.islast\n    label.delete(htf_label)\n    htf_label := label.new(bar_index + 2, htf_ema_f, (htf_bull_score > htf_bear_score ? \"15M \u25b2 BULL \" : htf_bear_score > htf_bull_score ? \"15M \u25bc BEAR \" : \"15M \u25c6 MIXED \") + str.tostring(math.max(htf_bull_score, htf_bear_score)) + \"/3\" + \"\\nEMA9:  \" + str.tostring(math.round(htf_ema_f, 5)) + \"\\nEMA21: \" + str.tostring(math.round(htf_ema_s, 5)), color=color.new(#161B22,5), textcolor=htf_bias_col, style=label.style_label_left, size=size.small)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// CURRENT TF FILTERS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nltf_ema_val = ta.ema(close, ltf_ema_len)\nltf_bull    = not use_ltf_ema or close > ltf_ema_val\nltf_bear    = not use_ltf_ema or close < ltf_ema_val\n\nplot(use_ltf_ema ? ltf_ema_val : na, \"TF EMA9\", color=color.new(#FFEB3B,60), linewidth=1, style=plot.style_circles)\n\nvol_ma      = ta.sma(volume, vol_len)\nvol_ok      = not use_vol_filter  or volume > vol_ma\nbody_ok     = not use_body_filter or math.abs(close - open) >= (atr14 * min_body_atr)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// KILL ZONE DETECTION (no input.session \u2014 plain time())\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nin_lon_raw = not na(time(\"\", \"0700-0800\", \"America/New_York\"))\nin_ny_raw  = not na(time(\"\", \"0930-1030\", \"America/New_York\"))\nin_mid_raw = not na(time(\"\", \"1300-1400\", \"America/New_York\"))\nin_asi_raw = not na(time(\"\", \"2000-0500\", \"America/New_York\"))\n\nuse_lon = trade_session == \"London Open\" or\n          trade_session == \"London Open + NY Open\" or\n          trade_session == \"London Open + NY Open + NY Midday\" or\n          trade_session == \"All Kill Zones\"\n\nuse_ny  = trade_session == \"NY Open\" or\n          trade_session == \"London Open + NY Open\" or\n          trade_session == \"London Open + NY Open + NY Midday\" or\n          trade_session == \"All Kill Zones\"\n\nuse_mid = trade_session == \"NY Midday\" or\n          trade_session == \"London Open + NY Open + NY Midday\" or\n          trade_session == \"All Kill Zones\"\n\nuse_asi = trade_session == \"Asian\" or\n          trade_session == \"All Kill Zones\"\n\nin_lon     = use_lon and in_lon_raw\nin_ny      = use_ny  and in_ny_raw\nin_mid     = use_mid and in_mid_raw\nin_asi     = use_asi and in_asi_raw\nin_session = in_lon or in_ny or in_mid or in_asi\n\nbgcolor(in_lon ? color.new(#42A5F5,91) : na, title=\"London Open\")\nbgcolor(in_ny  ? color.new(#66BB6A,91) : na, title=\"NY Open\")\nbgcolor(in_mid ? color.new(#EC407A,91) : na, title=\"NY Midday\")\nbgcolor(in_asi ? color.new(#AB47BC,91) : na, title=\"Asian Session\")\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// CRT PATTERN\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nc1_high = high[2]\nc1_low  = low[2]\nc2_high = high[1]\nc2_low  = low[1]\nc2_close = close[1]\nc2_open  = open[1]\n\nc2_rejected_from_high = c2_high > c1_high and c2_close < c1_high\nc2_rejected_from_low  = c2_low  < c1_low  and c2_close > c1_low\n\ncrt_bull = c2_rejected_from_low  and close > c1_high\ncrt_bear = c2_rejected_from_high and close < c1_low\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// FINAL SIGNAL\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfinal_bull = crt_bull and in_session and htf_bull_ok and ltf_bull and vol_ok and body_ok and show_bull_sig\nfinal_bear = crt_bear and in_session and htf_bear_ok and ltf_bear and vol_ok and body_ok and show_bear_sig\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// CRT BOX\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nif show_crt_boxes and (final_bull or final_bear)\n    box.new(bar_index - 2, c1_high, bar_index, c1_low, border_color=box_col, border_width=1, bgcolor=color.new(box_col,80))\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// MANIPULATION WICKS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nif show_manip_wicks and final_bull\n    line.new(bar_index - 1, c2_low, bar_index, c2_low, color=color.new(bull_col,30), width=2, style=line.style_dotted)\n\nif show_manip_wicks and final_bear\n    line.new(bar_index - 1, c2_high, bar_index, c2_high, color=color.new(bear_col,30), width=2, style=line.style_dotted)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// RR BOX\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nif show_rr_box and final_bull\n    entry_p = close\n    sl_p    = low  - atr14 * atr_mult_sl\n    tp_p    = entry_p + (entry_p - sl_p) * rr_ratio\n    risk    = entry_p - sl_p\n    reward  = tp_p    - entry_p\n    box.new(bar_index, tp_p, bar_index + rr_box_width, entry_p, border_color=color.new(#00E676,0), border_width=1, bgcolor=color.new(#00E676,85))\n    box.new(bar_index, entry_p, bar_index + rr_box_width, sl_p, border_color=color.new(#FF1744,0), border_width=1, bgcolor=color.new(#FF1744,85))\n    line.new(bar_index, entry_p, bar_index + rr_box_width, entry_p, color=color.new(color.white,15), width=1)\n    label.new(bar_index + rr_box_width, tp_p, \"  TP \" + str.tostring(rr_ratio) + \"R  +\" + str.tostring(math.round(reward,5)), color=color.new(#00E676,0), textcolor=color.white, style=label.style_label_left, size=size.small)\n    label.new(bar_index + rr_box_width, entry_p, \"  ENTRY \" + str.tostring(math.round(entry_p,5)), color=color.new(#21262D,0), textcolor=color.white, style=label.style_label_left, size=size.small)\n    label.new(bar_index + rr_box_width, sl_p, \"  SL  -\" + str.tostring(math.round(risk,5)), color=color.new(#FF1744,0), textcolor=color.white, style=label.style_label_left, size=size.small)\n\nif show_rr_box and final_bear\n    entry_p = close\n    sl_p    = high + atr14 * atr_mult_sl\n    tp_p    = entry_p - (sl_p - entry_p) * rr_ratio\n    risk    = sl_p    - entry_p\n    reward  = entry_p - tp_p\n    box.new(bar_index, entry_p, bar_index + rr_box_width, tp_p, border_color=color.new(#00E676,0), border_width=1, bgcolor=color.new(#00E676,85))\n    box.new(bar_index, sl_p, bar_index + rr_box_width, entry_p, border_color=color.new(#FF1744,0), border_width=1, bgcolor=color.new(#FF1744,85))\n    line.new(bar_index, entry_p, bar_index + rr_box_width, entry_p, color=color.new(color.white,15), width=1)\n    label.new(bar_index + rr_box_width, sl_p, \"  SL  +\" + str.tostring(math.round(risk,5)), color=color.new(#FF1744,0), textcolor=color.white, style=label.style_label_left, size=size.small)\n    label.new(bar_index + rr_box_width, entry_p, \"  ENTRY \" + str.tostring(math.round(entry_p,5)), color=color.new(#21262D,0), textcolor=color.white, style=label.style_label_left, size=size.small)\n    label.new(bar_index + rr_box_width, tp_p, \"  TP \" + str.tostring(rr_ratio) + \"R  -\" + str.tostring(math.round(reward,5)), color=color.new(#00E676,0), textcolor=color.white, style=label.style_label_left, size=size.small)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// SIGNAL LABELS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nlbl_size    = f_label_size(sig_label_size)\nsession_tag = in_lon ? \" [LON]\" : in_ny ? \" [NY]\" : in_mid ? \" [MID]\" : in_asi ? \" [ASIA]\" : \"\"\nhtf_score   = htf_bull_score > htf_bear_score ? htf_bull_score : htf_bear_score\n\nif final_bull\n    label.new(bar_index, low - atr14 * 1.2, \"\u25b2 SCALP BUY\" + session_tag + \"  15M \" + str.tostring(htf_score) + \"/3\", color=bull_col, textcolor=color.white, style=label.style_label_up, size=lbl_size)\n\nif final_bear\n    label.new(bar_index, high + atr14 * 1.2, \"\u25bc SCALP SELL\" + session_tag + \"  15M \" + str.tostring(htf_score) + \"/3\", color=bear_col, textcolor=color.white, style=label.style_label_down, size=lbl_size)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// ALERTS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nalertcondition(final_bull, title=\"CRT SCALP BUY\", message=\"\ud83d\udfe2 SCALP BUY | {{ticker}} | {{interval}} | Price: {{close}}\")\nalertcondition(final_bear, title=\"CRT SCALP SELL\", message=\"\ud83d\udd34 SCALP SELL | {{ticker}} | {{interval}} | Price: {{close}}\")\nalertcondition(final_bull or final_bear, title=\"CRT SCALP Signal\", message=\"\u26a1 SCALP SIGNAL | {{ticker}} | {{interval}} | Price: {{close}}\")\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// DASHBOARD\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nvar table dash = table.new(position.top_right, 2, 13, bgcolor=#0D1117, border_color=color.new(#42A5F5,40), border_width=1, frame_color=color.new(#42A5F5,20), frame_width=2)\n\nif barstate.islast\n    table.cell(dash, 0, 0, \"CRT SCALP \u00b7 15M HTF\", text_color=#42A5F5, text_size=size.small, bgcolor=#161B22, text_halign=text.align_center)\n    table.cell(dash, 1, 0, \"STATUS\", text_color=#42A5F5, text_size=size.small, bgcolor=#161B22, text_halign=text.align_center)\n    table.cell(dash, 0, 1, \"Scalp TF\", text_color=color.silver, text_size=size.tiny)\n    table.cell(dash, 1, 1, scalp_tf_ok ? \"\u2705 1M\u20135M OK\" : \"\u26a0 CHECK TF\", text_color=scalp_tf_ok ? #00E676 : #FFA726, text_size=size.tiny)\n\n    table.cell(dash, 0, 2, \"15M EMA9\", text_color=color.silver, text_size=size.tiny)\n    table.cell(dash, 1, 2, htf_c1_bull ? \"\u25b2 BULL\" : \"\u25bc BEAR\", text_color=htf_c1_bull ? #00E676 : #FF1744, text_size=size.tiny)\n\n    table.cell(dash, 0, 3, \"15M EMA21\", text_color=color.silver, text_size=size.tiny)\n    table.cell(dash, 1, 3, htf_c2_bull ? \"\u25b2 BULL\" : \"\u25bc BEAR\", text_color=htf_c2_bull ? #00E676 : #FF1744, text_size=size.tiny)\n\n    table.cell(dash, 0, 4, \"15M Structure\", text_color=color.silver, text_size=size.tiny)\n    table.cell(dash, 1, 4, htf_c3_bull ? \"\u25b2 BULL\" : \"\u25bc BEAR\", text_color=htf_c3_bull ? #00E676 : #FF1744, text_size=size.tiny)\n\n    table.cell(dash, 0, 5, \"15M Bias\", text_color=color.silver, text_size=size.tiny)\n    table.cell(dash, 1, 5, htf_bull_score >= htf_threshold ? \"\u2705 BULL \" + str.tostring(htf_bull_score) + \"/3\" : htf_bear_score >= htf_threshold ? \"\u2705 BEAR \" + str.tostring(htf_bear_score) + \"/3\" : \"\u26a0 MIXED\", text_color=htf_bull_score >= htf_threshold ? #00E676 : htf_bear_score >= htf_threshold ? #FF1744 : #FFA726, text_size=size.tiny)\n\n    table.cell(dash, 0, 6, \"Volume\", text_color=color.silver, text_size=size.tiny)\n    table.cell(dash, 1, 6, not use_vol_filter ? \"\u2014 OFF\" : vol_ok ? \"\u2705 ABOVE MA\" : \"\u26ab LOW\", text_color=vol_ok ? #00E676 : use_vol_filter ? #FF1744 : color.gray, text_size=size.tiny)\n\n    table.cell(dash, 0, 7, \"Body Filter\", text_color=color.silver, text_size=size.tiny)\n    table.cell(dash, 1, 7, not use_body_filter ? \"\u2014 OFF\" : body_ok ? \"\u2705 OK\" : \"\u26ab DOJI\", text_color=body_ok ? #00E676 : use_body_filter ? #FF1744 : color.gray, text_size=size.tiny)\n\n    table.cell(dash, 0, 8, \"London Open\", text_color=color.silver, text_size=size.tiny)\n    table.cell(dash, 1, 8, not use_lon ? \"\u2014 OFF\" : in_lon ? \"\ud83d\udfe2 ACTIVE\" : \"\u26ab WAITING\", text_color=in_lon ? #00E676 : use_lon ? color.gray : #363A45, text_size=size.tiny)\n\n    table.cell(dash, 0, 9, \"NY Open\", text_color=color.silver, text_size=size.tiny)\n    table.cell(dash, 1, 9, not use_ny ? \"\u2014 OFF\" : in_ny ? \"\ud83d\udfe2 ACTIVE\" : \"\u26ab WAITING\", text_color=in_ny ? #00E676 : use_ny ? color.gray : #363A45, text_size=size.tiny)\n\n    table.cell(dash, 0, 10, \"Asian\", text_color=color.silver, text_size=size.tiny)\n    table.cell(dash, 1, 10, not use_asi ? \"\u2014 OFF\" : in_asi ? \"\ud83d\udfe2 ACTIVE\" : \"\u26ab WAITING\", text_color=in_asi ? #00E676 : use_asi ? color.gray : #363A45, text_size=size.tiny)\n\n    table.cell(dash, 0, 11, \"CRT Setup\", text_color=color.silver, text_size=size.tiny)\n    table.cell(dash, 1, 11, c2_rejected_from_low  ? \"\u2b06 Bull Manip\" : c2_rejected_from_high ? \"\u2b07 Bear Manip\" : \"Scanning...\", text_color=c2_rejected_from_low ? #00E676 : c2_rejected_from_high ? #FF1744 : color.gray, text_size=size.tiny)\n\n    table.cell(dash, 0, 12, \"\u25b6 SIGNAL\", text_color=#42A5F5, text_size=size.tiny, bgcolor=#161B22)\n    table.cell(dash, 1, 12, final_bull ? \"\u25b2 BUY\" + session_tag : final_bear ? \"\u25bc SELL\" + session_tag : \"\u2014 Waiting \u2014\", text_color=final_bull ? #00E676 : final_bear ? #FF1744 : color.gray, text_size=size.small, bgcolor=#161B22)"
  },
  {
    "id": "ifvg.pine",
    "name": "FVG Asia Session [Sweep \u2192 FVG \u2192 RR]",
    "code": "// ============================================================\n// FVG ASIA SESSION  |  Pine Script v5\n// Trade only during Asia (00:00 \u2013 09:00 UTC)\n// Logic: Liquidity Sweep  \u2192  FVG forms  \u2192  Signal + RR zones\n// ============================================================\n//@version=5\nindicator(\"FVG Asia Session [Sweep \u2192 FVG \u2192 RR]\",\n     shorttitle = \"FVG ASIA\",\n     overlay    = true,\n     max_lines_count  = 500,\n     max_boxes_count  = 500,\n     max_labels_count = 500)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  INPUTS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\ngrp_sess = \"\u2550\u2550\u2550  Asia Session  \u2550\u2550\u2550\"\ni_asiaStart = input.int(0,  \"Session Start (UTC hour)\", minval=0, maxval=23, group=grp_sess,\n     tooltip=\"Default 0 = midnight UTC = 07:00 Bangkok / 08:00 Singapore / Tokyo.\")\ni_asiaEnd   = input.int(9,  \"Session End   (UTC hour)\", minval=1, maxval=23, group=grp_sess,\n     tooltip=\"Default 9 = 09:00 UTC = 16:00 Bangkok / 17:00 Singapore.\")\ni_shadeAsia = input.bool(true, \"Shade Asia Session Background\", group=grp_sess)\n\ngrp_liq = \"\u2550\u2550\u2550  Liquidity Sweep  \u2550\u2550\u2550\"\ni_pivLen    = input.int  (3,    \"Pivot Length (bars each side)\", minval=1, maxval=10, group=grp_liq,\n     tooltip=\"Bars left/right to confirm a swing high/low.\")\ni_liqWin    = input.int  (10,   \"Sweep Memory (bars)\",           minval=2, maxval=30,  group=grp_liq,\n     tooltip=\"After a sweep, signal is valid for this many bars while waiting for the FVG.\")\ni_liqBuf    = input.float(0.0,  \"Sweep Buffer (%)\",              minval=0.0, step=0.01, group=grp_liq,\n     tooltip=\"Price must pierce the pivot by at least this % to count as a sweep.\")\ni_showSwMark = input.bool(true, \"Show Sweep Marker on Chart\",   group=grp_liq,\n     tooltip=\"Paint a diamond on the candle that swept the pivot level.\")\n\ngrp_fvg = \"\u2550\u2550\u2550  FVG Detection  \u2550\u2550\u2550\"\ni_minGapPct = input.float(0.05, \"Min Gap Size (%)\", minval=0.0, step=0.01, group=grp_fvg,\n     tooltip=\"Minimum size of the imbalance gap as % of price. Reduce for crypto/indices.\")\ni_dir       = input.string(\"Both\", \"Signal Direction\",\n     options=[\"Both\",\"Bullish Only\",\"Bearish Only\"], group=grp_fvg)\n\ngrp_rr = \"\u2550\u2550\u2550  Risk / Reward  \u2550\u2550\u2550\"\ni_entryType = input.string(\"FVG Mid\", \"Entry at\",\n     options=[\"FVG Mid\",\"FVG Edge\",\"Close\"], group=grp_rr,\n     tooltip=\"FVG Mid = midpoint of the gap (recommended for Asia). FVG Edge = near side. Close = signal bar close.\")\ni_slType    = input.string(\"Gap Edge\", \"Stop-Loss at\",\n     options=[\"Gap Edge\",\"Last Pivot\",\"Lookback\"], group=grp_rr,\n     tooltip=\"Gap Edge = tight SL just past the far side of the gap (recommended). Last Pivot = swept pivot. Lookback = n-bar extreme.\")\ni_slLookback = input.int  (5,   \"SL Lookback (bars)\", minval=1, maxval=30, group=grp_rr)\ni_slBuf      = input.float(0.1, \"SL Buffer (%)\",      minval=0.0, step=0.05, group=grp_rr)\ni_rr1        = input.float(1.5, \"TP1 R:R\",            minval=0.1, step=0.1,  group=grp_rr)\ni_rr2        = input.float(3.0, \"TP2 R:R\",            minval=0.1, step=0.1,  group=grp_rr)\n\ngrp_vis = \"\u2550\u2550\u2550  Visuals  \u2550\u2550\u2550\"\ni_extBars    = input.int  (40,  \"Box Extend Right (bars)\", minval=5, maxval=500, group=grp_vis)\ni_bullCol    = input.color(color.new(#00e676, 0), \"Bullish Color\", group=grp_vis)\ni_bearCol    = input.color(color.new(#ff1744, 0), \"Bearish Color\", group=grp_vis)\ni_alpha      = input.int  (82,  \"Box Transparency\",        minval=0, maxval=99, group=grp_vis)\ni_showGap    = input.bool (true, \"Shade FVG Gap Zone\",     group=grp_vis)\ni_showLabels = input.bool (true, \"Show Price Labels\",      group=grp_vis)\ni_showDash   = input.bool (true, \"Show Dashboard\",         group=grp_vis)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  ASIA SESSION GATE\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nutcH     = hour(time, \"UTC\")\ninAsia   = utcH >= i_asiaStart and utcH < i_asiaEnd\n\n// Background shading\nbgcolor(i_shadeAsia and inAsia ? color.new(#4a148c, 91) : na, title=\"Asia Background\")\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  TREND & STRUCTURE  (for score / filter)\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nema20 = ta.ema(close, 20)\nema50 = ta.ema(close, 50)\ntrendUp   = ema20 > ema50\ntrendDown = ema20 < ema50\n\nswH = ta.pivothigh(high, 3, 3)\nswL = ta.pivotlow (low,  3, 3)\nvar float lastSH = na\nvar float lastSL = na\nif not na(swH)\n    lastSH := swH\nif not na(swL)\n    lastSL := swL\n\nbullStruct = not na(lastSL) and close > lastSL\nbearStruct = not na(lastSH) and close < lastSH\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  LIQUIDITY SWEEP DETECTION\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// Pivot-based: track the most-recent confirmed pivot H/L.\n// Sweep = wick through pivot by >= buffer  +  close reverses back.\n\npivH = ta.pivothigh(high, i_pivLen, i_pivLen)\npivL = ta.pivotlow (low,  i_pivLen, i_pivLen)\n\nvar float rPivH = na   // most recent confirmed pivot high\nvar float rPivL = na   // most recent confirmed pivot low\nif not na(pivH)\n    rPivH := pivH\nif not na(pivL)\n    rPivL := pivL\n\n// Sweep conditions (only valid inside Asia session)\nbullSwNow = inAsia and not na(rPivL) and low  < rPivL * (1 - i_liqBuf / 100) and close > rPivL  // wick below, close back above\nbearSwNow = inAsia and not na(rPivH) and high > rPivH * (1 + i_liqBuf / 100) and close < rPivH  // wick above, close back below\n\n// Remember sweep for i_liqWin bars so FVG forming 1\u20133 bars later still qualifies\nvar int bullSwAge = 999\nvar int bearSwAge = 999\nif bullSwNow\n    bullSwAge := 0\nelse\n    bullSwAge := math.min(bullSwAge + 1, 999)\nif bearSwNow\n    bearSwAge := 0\nelse\n    bearSwAge := math.min(bearSwAge + 1, 999)\n\nbullLiqReady = bullSwAge <= i_liqWin    // sweep happened recently (bull setup)\nbearLiqReady = bearSwAge <= i_liqWin    // sweep happened recently (bear setup)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  FVG DETECTION  (3-candle imbalance)\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// Bullish FVG : gap between high[2] and low[0]  \u2192  high[2] < low[0]\n//   After a bullish sweep (sweeping lows), price impulses UP leaving a gap.\n//   Entry = retrace into the FVG zone to go long.\n//\n// Bearish FVG : gap between low[2] and high[0]  \u2192  low[2] > high[0]\n//   After a bearish sweep (sweeping highs), price impulses DOWN leaving a gap.\n//   Entry = retrace into the FVG zone to go short.\n\nminGap = close * i_minGapPct / 100\n\n// Bullish FVG: gap between candle[-2].high and candle[0].low (price shot up)\nrawBull = high[2] < low[0] and (low[0] - high[2]) >= minGap\n\n// Bearish FVG: gap between candle[-2].low and candle[0].high (price shot down)\nrawBear = low[2] > high[0] and (low[2] - high[0]) >= minGap\n\n// Gap boundaries\nbullGapTop = low[0]    // top of the bullish FVG\nbullGapBot = high[2]   // bottom of the bullish FVG\nbearGapTop = low[2]    // top of the bearish FVG\nbearGapBot = high[0]   // bottom of the bearish FVG\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  FINAL SIGNAL\n//     FVG formed  +  sweep happened recently  +  in Asia session\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nbullSig = rawBull and bullLiqReady and inAsia and trendUp and bullStruct\nbullSig := bullSig and (i_dir == \"Both\" or i_dir == \"Bullish Only\")\n\nbearSig = rawBear and bearLiqReady and inAsia and trendDown and bearStruct\nbearSig := bearSig and (i_dir == \"Both\" or i_dir == \"Bearish Only\")\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  ENTRY / SL / TP  LEVELS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n// Bull levels\nbullEntry = i_entryType == \"FVG Mid\"  ? (bullGapTop + bullGapBot) / 2 : i_entryType == \"FVG Edge\" ? bullGapBot : close\nbullSL    = i_slType == \"Gap Edge\"    ? bullGapBot * (1 - i_slBuf / 100) : i_slType == \"Last Pivot\" ? (not na(rPivL) ? rPivL * (1 - i_slBuf / 100) : bullGapBot * (1 - i_slBuf / 100)) : ta.lowest(low, i_slLookback) * (1 - i_slBuf / 100)\nbullRisk  = math.max(math.abs(bullEntry - bullSL), syminfo.mintick)\nbullTP1   = bullEntry + bullRisk * i_rr1\nbullTP2   = bullEntry + bullRisk * i_rr2\n\n// Bear levels\nbearEntry = i_entryType == \"FVG Mid\"  ? (bearGapTop + bearGapBot) / 2 : i_entryType == \"FVG Edge\" ? bearGapTop : close\nbearSL    = i_slType == \"Gap Edge\"    ? bearGapTop * (1 + i_slBuf / 100) : i_slType == \"Last Pivot\" ? (not na(rPivH) ? rPivH * (1 + i_slBuf / 100) : bearGapTop * (1 + i_slBuf / 100)) : ta.highest(high, i_slLookback) * (1 + i_slBuf / 100)\nbearRisk  = math.max(math.abs(bearSL - bearEntry), syminfo.mintick)\nbearTP1   = bearEntry - bearRisk * i_rr1\nbearTP2   = bearEntry - bearRisk * i_rr2\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  PLOTSHAPE  (must be in global scope)\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n// Main signals\nplotshape(bullSig, title=\"Bull FVG Asia\",\n     style=shape.triangleup, location=location.belowbar,\n     color=i_bullCol, size=size.normal)\n\nplotshape(bearSig, title=\"Bear FVG Asia\",\n     style=shape.triangledown, location=location.abovebar,\n     color=i_bearCol, size=size.normal)\n\n// Sweep markers (small diamonds)\nplotshape(i_showSwMark and bullSwNow, title=\"Bull Sweep\",\n     style=shape.diamond, location=location.belowbar,\n     color=color.new(#00e676, 15), size=size.small)\n\nplotshape(i_showSwMark and bearSwNow, title=\"Bear Sweep\",\n     style=shape.diamond, location=location.abovebar,\n     color=color.new(#ff1744, 15), size=size.small)\n\n// EMAs\nplot(ema20, \"EMA 20\", color=color.new(color.orange, 50), linewidth=1)\nplot(ema50, \"EMA 50\", color=color.new(color.blue,   50), linewidth=1)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  DRAW R:R BOXES + LINES + LABELS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nvar box   bxGap  = na\nvar box   bxSL   = na\nvar box   bxTP1  = na\nvar box   bxTP2  = na\nvar line  lnEnt  = na\nvar line  lnSL   = na\nvar line  lnTP1  = na\nvar line  lnTP2  = na\nvar label lbEnt  = na\nvar label lbSL   = na\nvar label lbTP1  = na\nvar label lbTP2  = na\n\nvar string lastSig   = \"\u2014\"\nvar int    sigCount  = 0\nvar int    lastScore = 0\n\n// \u2500\u2500 BULLISH \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nif bullSig\n    sigCount += 1\n    lastSig  := \"Bullish\"\n    R = bar_index + i_extBars\n\n    // FVG gap highlight\n    if i_showGap\n        bxGap := box.new(bar_index - 2, bullGapTop, R, bullGapBot,\n             border_color=color.new(i_bullCol, 55),\n             bgcolor     =color.new(i_bullCol, 73))\n\n    // SL zone (red)\n    bxSL  := box.new(bar_index, bullEntry, R, bullSL,\n         border_color=i_bearCol, bgcolor=color.new(i_bearCol, i_alpha))\n    // TP1 zone\n    bxTP1 := box.new(bar_index, bullTP1,   R, bullEntry,\n         border_color=i_bullCol, bgcolor=color.new(i_bullCol, i_alpha))\n    // TP2 zone (lighter)\n    bxTP2 := box.new(bar_index, bullTP2,   R, bullTP1,\n         border_color=color.new(i_bullCol, 40),\n         bgcolor=color.new(i_bullCol, math.min(i_alpha + 7, 99)))\n\n    lnEnt  := line.new(bar_index, bullEntry, R, bullEntry, color=color.white,           width=2, style=line.style_dashed)\n    lnSL   := line.new(bar_index, bullSL,    R, bullSL,    color=i_bearCol,             width=1, style=line.style_solid)\n    lnTP1  := line.new(bar_index, bullTP1,   R, bullTP1,   color=i_bullCol,             width=1, style=line.style_dotted)\n    lnTP2  := line.new(bar_index, bullTP2,   R, bullTP2,   color=color.new(i_bullCol,40),width=1,style=line.style_dotted)\n\n    if i_showLabels\n        lbEnt  := label.new(R, bullEntry, \"Entry  \" + str.tostring(math.round(bullEntry, 2)),\n             style=label.style_label_left, color=color.new(#1a1a2e,5), textcolor=color.white, size=size.small)\n        lbSL   := label.new(R, bullSL,    \"SL  \"    + str.tostring(math.round(bullSL,    2)),\n             style=label.style_label_left, color=color.new(i_bearCol,10), textcolor=color.white, size=size.small)\n        lbTP1  := label.new(R, bullTP1,   \"TP1 (\" + str.tostring(i_rr1) + \"R)  \" + str.tostring(math.round(bullTP1, 2)),\n             style=label.style_label_left, color=color.new(i_bullCol,10), textcolor=color.white, size=size.small)\n        lbTP2  := label.new(R, bullTP2,   \"TP2 (\" + str.tostring(i_rr2) + \"R)  \" + str.tostring(math.round(bullTP2, 2)),\n             style=label.style_label_left, color=color.new(i_bullCol,35), textcolor=color.white, size=size.small)\n\n// \u2500\u2500 BEARISH \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nif bearSig\n    sigCount += 1\n    lastSig  := \"Bearish\"\n    R = bar_index + i_extBars\n\n    if i_showGap\n        bxGap := box.new(bar_index - 2, bearGapTop, R, bearGapBot,\n             border_color=color.new(i_bearCol, 55),\n             bgcolor     =color.new(i_bearCol, 73))\n\n    bxSL  := box.new(bar_index, bearSL,    R, bearEntry,\n         border_color=i_bearCol, bgcolor=color.new(i_bearCol, i_alpha))\n    bxTP1 := box.new(bar_index, bearEntry, R, bearTP1,\n         border_color=i_bullCol, bgcolor=color.new(i_bullCol, i_alpha))\n    bxTP2 := box.new(bar_index, bearTP1,   R, bearTP2,\n         border_color=color.new(i_bullCol, 40),\n         bgcolor=color.new(i_bullCol, math.min(i_alpha + 7, 99)))\n\n    lnEnt  := line.new(bar_index, bearEntry, R, bearEntry, color=color.white,           width=2, style=line.style_dashed)\n    lnSL   := line.new(bar_index, bearSL,    R, bearSL,    color=i_bearCol,             width=1, style=line.style_solid)\n    lnTP1  := line.new(bar_index, bearTP1,   R, bearTP1,   color=i_bullCol,             width=1, style=line.style_dotted)\n    lnTP2  := line.new(bar_index, bearTP2,   R, bearTP2,   color=color.new(i_bullCol,40),width=1,style=line.style_dotted)\n\n    if i_showLabels\n        lbEnt  := label.new(R, bearEntry, \"Entry  \" + str.tostring(math.round(bearEntry, 2)),\n             style=label.style_label_left, color=color.new(#1a1a2e,5), textcolor=color.white, size=size.small)\n        lbSL   := label.new(R, bearSL,    \"SL  \"    + str.tostring(math.round(bearSL,    2)),\n             style=label.style_label_left, color=color.new(i_bearCol,10), textcolor=color.white, size=size.small)\n        lbTP1  := label.new(R, bearTP1,   \"TP1 (\" + str.tostring(i_rr1) + \"R)  \" + str.tostring(math.round(bearTP1, 2)),\n             style=label.style_label_left, color=color.new(i_bullCol,10), textcolor=color.white, size=size.small)\n        lbTP2  := label.new(R, bearTP2,   \"TP2 (\" + str.tostring(i_rr2) + \"R)  \" + str.tostring(math.round(bearTP2, 2)),\n             style=label.style_label_left, color=color.new(i_bullCol,35), textcolor=color.white, size=size.small)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  DASHBOARD\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nvar table dash = table.new(position.top_right, 2, 10,\n     border_width=1,\n     border_color=color.new(color.gray, 55),\n     bgcolor     =color.new(#1a1a2e, 8))\n\nif i_showDash and barstate.islast\n    // Header\n    hdrCol = inAsia ? color.new(#4a148c, 15) : color.new(#37474f, 40)\n    table.cell(dash, 0, 0, \"FVG  ASIA  SESSION\", text_color=color.white, bgcolor=hdrCol, text_size=size.normal, text_halign=text.align_center)\n    table.cell(dash, 1, 0, inAsia ? \"ACTIVE\" : \"OFF-HOURS\", text_color=color.white, bgcolor=hdrCol, text_size=size.normal, text_halign=text.align_center)\n\n    // Session clock\n    asiaStr = \"UTC \" + str.tostring(i_asiaStart) + \":00 \u2013 \" + str.tostring(i_asiaEnd) + \":00  |  Now \" + str.tostring(utcH) + \"h UTC\"\n    table.cell(dash, 0, 1, \"Session Window\", text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 1, asiaStr, text_color=color.white, bgcolor=inAsia ? color.new(#4a148c, 45) : color.new(color.gray, 50))\n\n    // Trend\n    trendLbl = trendUp ? \"Up (EMA20>50)\" : trendDown ? \"Down (EMA20<50)\" : \"Ranging\"\n    trendCol = trendUp ? color.new(#00e676, 25) : trendDown ? color.new(#ff1744, 25) : color.new(color.gray, 25)\n    table.cell(dash, 0, 2, \"Trend\", text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 2, trendLbl, text_color=color.white, bgcolor=trendCol)\n\n    // Structure\n    strLbl = bullStruct ? \"Bullish (above SwL)\" : bearStruct ? \"Bearish (below SwH)\" : \"Neutral\"\n    strCol = bullStruct ? color.new(#00e676, 40) : bearStruct ? color.new(#ff1744, 40) : color.new(color.gray, 40)\n    table.cell(dash, 0, 3, \"Structure\", text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 3, strLbl, text_color=color.white, bgcolor=strCol)\n\n    // Bull sweep state\n    bSwLbl = bullSwNow ? \"SWEPT  now\" : bullLiqReady ? \"Ready  \" + str.tostring(bullSwAge) + \"b ago\" : \"Waiting\"\n    bSwCol = bullSwNow ? color.new(#00e676, 10) : bullLiqReady ? color.new(color.orange, 25) : color.new(color.gray, 55)\n    table.cell(dash, 0, 4, \"Bull Sweep\", text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 4, bSwLbl, text_color=color.white, bgcolor=bSwCol)\n\n    // Bear sweep state\n    rSwLbl = bearSwNow ? \"SWEPT  now\" : bearLiqReady ? \"Ready  \" + str.tostring(bearSwAge) + \"b ago\" : \"Waiting\"\n    rSwCol = bearSwNow ? color.new(#ff1744, 10) : bearLiqReady ? color.new(color.orange, 25) : color.new(color.gray, 55)\n    table.cell(dash, 0, 5, \"Bear Sweep\", text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 5, rSwLbl, text_color=color.white, bgcolor=rSwCol)\n\n    // Last signal\n    sigCol = lastSig == \"Bullish\" ? color.new(#00e676, 30) : lastSig == \"Bearish\" ? color.new(#ff1744, 30) : color.new(color.gray, 50)\n    table.cell(dash, 0, 6, \"Last Signal\", text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 6, lastSig, text_color=color.white, bgcolor=sigCol)\n\n    // R:R\n    table.cell(dash, 0, 7, \"R:R  TP1 / TP2\", text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 7, str.tostring(i_rr1) + \"R  /  \" + str.tostring(i_rr2) + \"R\", text_color=color.white, bgcolor=color.new(color.gray, 50))\n\n    // Entry mode\n    table.cell(dash, 0, 8, \"Entry / SL Mode\", text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 8, i_entryType + \"  /  \" + i_slType, text_color=color.white, bgcolor=color.new(color.gray, 50))\n\n    // Total signals\n    table.cell(dash, 0, 9, \"Total Signals\", text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 9, str.tostring(sigCount), text_color=color.white, bgcolor=color.new(color.gray, 50))\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  ALERTS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nalertcondition(bullSig, title=\"Asia Bull FVG Signal\",\n     message=\"ASIA BULL FVG on {{ticker}} @ {{close}} | Sweep cleared, FVG Entry/SL/TP plotted.\")\nalertcondition(bearSig, title=\"Asia Bear FVG Signal\",\n     message=\"ASIA BEAR FVG on {{ticker}} @ {{close}} | Sweep cleared, FVG Entry/SL/TP plotted.\")\nalertcondition(bullSig or bearSig, title=\"Asia FVG Signal (Any)\",\n     message=\"ASIA FVG Signal on {{ticker}} @ {{close}} | Liquidity swept, FVG confirmed.\")\nalertcondition(bullSwNow, title=\"Asia Bull Sweep\",\n     message=\"ASIA BULL SWEEP on {{ticker}} @ {{close}} | Pivot low taken, watching for FVG.\")\nalertcondition(bearSwNow, title=\"Asia Bear Sweep\",\n     message=\"ASIA BEAR SWEEP on {{ticker}} @ {{close}} | Pivot high taken, watching for FVG.\")"
  },
  {
    "id": "crt_tbs.pine",
    "name": "Crt Tbs",
    "code": "// ============================================================\n// CRT + TBS [Turtle Body Soup]  |  Pine Script v5\n// Candle Range Theory  +  Turtle Body Soup Entry Method\n// ============================================================\n//\n// WHAT IS CRT?  (3-candle AMD model)\n//   C1 \u2014 Accumulation  : establishes the reference range (high/low)\n//   C2 \u2014 Manipulation  : sweeps C1's high or low to grab liquidity\n//   C3 \u2014 Distribution  : reversal + close beyond the other side of C1\n//\n// WHAT IS TBS?  (Turtle Body Soup)\n//   The BODY of C2 closes BEYOND C1's high or low.\n//   This is stronger than TWS (Turtle Wick Soup) where only the wick pierces.\n//   TBS = institutional trap confirmed by candle body close \u2192 high-prob reversal.\n//\n//   TBS BULL:  C2 body closes BELOW C1 low  \u2192  then C3 reclaims and reverses UP\n//   TBS BEAR:  C2 body closes ABOVE C1 high \u2192  then C3 reclaims and reverses DOWN\n//\n// KILL ZONES  (ICT Session Windows)\n//   Asia:     20:00 \u2013 23:00 ET   (sets the range / accumulation)\n//   London:   02:00 \u2013 05:00 ET   (main manipulation + distribution)\n//   NY AM:    08:30 \u2013 11:00 ET   (second high-prob manipulation window)\n//   NY PM:    13:00 \u2013 16:00 ET   (London-close / NY continuation)\n//\n// SIGNAL LOGIC (all must be TRUE):\n//   \u2705 CRT 3-candle pattern confirmed\n//   \u2705 C2 is TBS (body close beyond C1 level, not just wick)\n//   \u2705 Inside selected Kill Zone session\n//   \u2705 HTF alignment (optional): 1H EMA / candle structure agrees\n// ============================================================\n\n//@version=5\nindicator(\"CRT + TBS [Turtle Body Soup]\", shorttitle = \"CRT+TBS\", overlay = true, max_labels_count = 500, max_lines_count = 500, max_boxes_count = 500)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  INPUTS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\ngrp_kz    = \"\u23f0  Kill Zone Sessions (ET / New York Time)\"\ngrp_crt   = \"\u2699\ufe0f  CRT + TBS Detection\"\ngrp_trend = \"\ud83d\udcc8  Trend Filter (Trading Style)\"\ngrp_htf   = \"\ud83d\udcd0  HTF Alignment (1H)\"\ngrp_rr    = \"\ud83c\udfaf  Entry / Risk / Reward\"\ngrp_vis   = \"\ud83c\udfa8  Visuals\"\n\n// \u2500\u2500 Kill Zones \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ni_kzMode = input.string(\"London + NY AM\", \"Active Kill Zones\", options=[\"Asia Only\",\"London Only\",\"NY AM Only\",\"NY PM Only\", \"London + NY AM\",\"London + NY PM\",\"All Sessions\"], group=grp_kz, tooltip=\"Signals only fire inside the selected session window(s).\")\n\ni_asiaStart  = input.int(20, \"Asia  Start (ET hour)\", minval=0, maxval=23, group=grp_kz)\ni_asiaEnd    = input.int(23, \"Asia  End   (ET hour)\", minval=0, maxval=23, group=grp_kz)\ni_lonStart   = input.int(2,  \"London Start (ET hour)\",minval=0, maxval=23, group=grp_kz)\ni_lonEnd     = input.int(5,  \"London End   (ET hour)\",minval=0, maxval=23, group=grp_kz)\ni_nyAMStart  = input.int(8,  \"NY AM Start  (ET hour)\",minval=0, maxval=23, group=grp_kz,\n     tooltip=\"NY morning kill zone starts at 08:30 ET \u2014 use 8 here.\")\ni_nyAMEnd    = input.int(11, \"NY AM End    (ET hour)\",minval=0, maxval=23, group=grp_kz)\ni_nyPMStart  = input.int(13, \"NY PM Start  (ET hour)\",minval=0, maxval=23, group=grp_kz)\ni_nyPMEnd    = input.int(16, \"NY PM End    (ET hour)\",minval=0, maxval=23, group=grp_kz)\ni_shadeSess  = input.bool(true, \"Shade Session Background\", group=grp_kz)\n\n// \u2500\u2500 CRT + TBS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ni_tbsOnly = input.bool(true, \"Require TBS (body close beyond level)\", group=grp_crt, tooltip=\"ON = Turtle BODY Soup only (body of C2 closes past C1 level) \u2014 HIGHER QUALITY\\nOFF = also accept Turtle WICK Soup (wick pierces, body stays inside) \u2014 MORE SIGNALS\")\ni_showC1Box  = input.bool(true,  \"Show C1 Accumulation Box\",              group=grp_crt)\ni_showC2Mk   = input.bool(true,  \"Show C2 Manipulation Wick/Body Mark\",   group=grp_crt)\ni_showDir = input.string(\"Both\", \"Signal Direction\", options=[\"Both\",\"Bullish Only\",\"Bearish Only\"], group=grp_crt)\n\n// \u2500\u2500 HTF \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ni_useHTF     = input.bool(true,  \"Enable 1H HTF Alignment Filter\", group=grp_htf)\ni_htfTF      = input.timeframe(\"60\", \"HTF Timeframe\", group=grp_htf)\ni_htfEmaLen  = input.int(50, \"HTF EMA Length (trend bias)\", minval=5, group=grp_htf,\n     tooltip=\"Price must be above (bull) or below (bear) this EMA on the HTF.\")\ni_htfStrict  = input.bool(false, \"Require BOTH HTF EMA + HTF Candle\",    group=grp_htf,\n     tooltip=\"ON = HTF EMA bias AND last HTF candle must agree (stricter)\\nOFF = HTF EMA alone is sufficient\")\ni_showHTFEma = input.bool(true,  \"Show HTF EMA on chart\", group=grp_htf)\n\n// \u2500\u2500 Trend Filter \u2014 Trading Style \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ni_tradingStyle = input.string(\"Intraday\", \"Trading Style\", options=[\"Scalping\",\"Intraday\",\"Swing\"], group=grp_trend, tooltip=\"Scalping  \u2192 EMA 8 / 21  (fast, 1m\u20135m)\\nIntraday  \u2192 EMA 20 / 50  (medium, 15m\u20131H)\\nSwing     \u2192 EMA 50 / 200 (slow, 4H\u2013Daily)\\nSignals only fire in the direction of the current trend (faster EMA above/below slower EMA).\")\ni_useTrend   = input.bool(true, \"Enable Trend Filter\", group=grp_trend,\n     tooltip=\"When ON, only LONG signals are allowed when trend is UP, only SHORT when trend is DOWN.\")\ni_showTrendEma = input.bool(true, \"Show Trend EMAs on chart\", group=grp_trend)\ni_trendEmaFast = input.int(0,  \"Custom Fast EMA (0 = use Style default)\", minval=0, group=grp_trend,\n     tooltip=\"Leave 0 to auto-select based on Trading Style. Set a custom value to override.\")\ni_trendEmaSlow = input.int(0,  \"Custom Slow EMA (0 = use Style default)\", minval=0, group=grp_trend,\n     tooltip=\"Leave 0 to auto-select based on Trading Style. Set a custom value to override.\")\n\n// \u2500\u2500 Entry / RR \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ni_entryAt = input.string(\"C1 Mid\", \"Entry At\", options=[\"C1 Mid\",\"C3 Close\",\"C1 Opposite Edge\"], group=grp_rr, tooltip=\"C1 Mid = midpoint of the C1 accumulation range (recommended)\\nC3 Close = signal bar close (immediate market entry)\\nC1 Opposite Edge = conservative end of C1 range\")\ni_slAt = input.string(\"C2 Extreme\", \"Stop-Loss At\", options=[\"C2 Extreme\",\"C1 Edge\",\"ATR\"], group=grp_rr, tooltip=\"C2 Extreme = beyond the wick that manipulated (tightest SL)\\nC1 Edge = beyond the C1 range boundary (wider, safer)\\nATR = ATR-based SL\")\ni_slBuf      = input.float(0.05, \"SL Buffer (%)\", minval=0.0, step=0.05, group=grp_rr)\ni_atrSLMult  = input.float(1.0,  \"ATR SL Multiplier\", minval=0.1, step=0.1, group=grp_rr)\ni_tp1R       = input.float(1.5,  \"TP1 R:R\", minval=0.1, step=0.1, group=grp_rr)\ni_tp2R       = input.float(3.0,  \"TP2 R:R\", minval=0.1, step=0.1, group=grp_rr)\ni_boxBars    = input.int(30, \"RR Box Width (bars)\", minval=5, maxval=200, group=grp_rr)\n\n// \u2500\u2500 Visuals \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ni_bullCol    = input.color(color.new(#00e676, 0),  \"Bullish Color\", group=grp_vis)\ni_bearCol    = input.color(color.new(#ff1744, 0),  \"Bearish Color\", group=grp_vis)\ni_c1Col      = input.color(color.new(#ffa726, 0),  \"C1 Range Box Color\", group=grp_vis)\ni_alpha      = input.int  (82, \"Box Transparency\", minval=0, maxval=99, group=grp_vis)\ni_showLabels = input.bool (true, \"Show Entry/SL/TP Labels\", group=grp_vis)\ni_showDash   = input.bool (true, \"Show Dashboard\", group=grp_vis)\ni_lblSize = input.string(\"small\", \"Label Size\", options=[\"tiny\",\"small\",\"normal\",\"large\"], group=grp_vis)\n\n// \u2500\u2500 Volume & MSS Filters \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ngrp_vols     = \"\ud83d\udcca  Volume & Structure (Extra Confluence)\"\ni_volFilter  = input.bool(true,  \"Enable Volume Exhaustion (C2)\", group=grp_vols,\n     tooltip=\"Confirms that the Manipulation candle (C2) had high volume (institutional stop run).\")\ni_mssFilter = input.bool(false, \"Require Market Structure Shift (MSS)\", group=grp_vols, tooltip=\"C3 must not only close beyond C1, but also break the mini-swing high/low of the range.\")\ni_volMALen   = input.int(20, \"Volume MA Length\", minval=5, group=grp_vols)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  UTILITIES\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\natr14     = ta.atr(14)\netH       = hour(time, \"America/New_York\")\nf_price(p) => str.tostring(math.round(p, syminfo.mintick > 0.001 ? 2 : 5))\nf_lsize(s) =>\n    s == \"tiny\" ? size.tiny : s == \"small\" ? size.small : s == \"large\" ? size.large : size.normal\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  KILL ZONE SESSION DETECTION  (ET / NY Time)\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\ninAsia  = etH >= i_asiaStart and etH < i_asiaEnd\ninLon   = etH >= i_lonStart and etH < i_lonEnd\ninNYAM  = etH >= i_nyAMStart and etH < i_nyAMEnd\ninNYPM  = etH >= i_nyPMStart and etH < i_nyPMEnd\n\nuseAsia = i_kzMode == \"Asia Only\" or i_kzMode == \"All Sessions\"\nuseLon  = str.contains(i_kzMode, \"London\") or i_kzMode == \"All Sessions\"\nuseNYAM = str.contains(i_kzMode, \"NY AM\") or i_kzMode == \"All Sessions\"\nuseNYPM = str.contains(i_kzMode, \"NY PM\") or i_kzMode == \"All Sessions\"\n\n// Re-implement with clean logic\nuseAsia2 = i_kzMode == \"Asia Only\" or i_kzMode == \"All Sessions\"\nuseLon2  = i_kzMode == \"London Only\" or i_kzMode == \"London + NY AM\" or i_kzMode == \"London + NY PM\" or i_kzMode == \"All Sessions\"\nuseNYAM2 = i_kzMode == \"NY AM Only\" or i_kzMode == \"London + NY AM\" or i_kzMode == \"All Sessions\"\nuseNYPM2 = i_kzMode == \"NY PM Only\" or i_kzMode == \"London + NY PM\" or i_kzMode == \"All Sessions\"\n\nactiveAsia = useAsia2 and inAsia\nactiveLon  = useLon2  and inLon\nactiveNYAM = useNYAM2 and inNYAM\nactiveNYPM = useNYPM2 and inNYPM\ninKZ = activeAsia or activeLon or activeNYAM or activeNYPM\n\n// Session background  (bgcolor must be global scope in Pine Script v5)\nbgcolor(i_shadeSess and activeLon  ? color.new(#1565c0, 91) : na, title=\"London BG\")\nbgcolor(i_shadeSess and activeNYAM ? color.new(#1b5e20, 91) : na, title=\"NY AM BG\")\nbgcolor(i_shadeSess and activeNYPM ? color.new(#0d47a1, 91) : na, title=\"NY PM BG\")\nbgcolor(i_shadeSess and activeAsia ? color.new(#4a148c, 91) : na, title=\"Asia BG\")\n\n// Session name tag\nkzTag = activeLon ? \"[LON]\" : activeNYAM ? \"[NY AM]\" : activeNYPM ? \"[NY PM]\" : activeAsia ? \"[ASIA]\" : \"\"\n\n// Kill zone open marker\nkzName = activeLon ? \"LONDON KZ\" : activeNYAM ? \"NY AM KZ\" : activeNYPM ? \"NY PM KZ\" : activeAsia ? \"ASIA KZ\" : \"\"\nvar string prevKZ = \"\"\nif inKZ and kzName != prevKZ\n    label.new(bar_index, high, kzName, style=label.style_label_down, color=color.new(#263238, 25), textcolor=color.white, size=size.tiny)\n    prevKZ := kzName\nif not inKZ\n    prevKZ := \"\"\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  HTF ALIGNMENT  (1H EMA + structure)\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nhtfEma  = request.security(syminfo.tickerid, i_htfTF, ta.ema(close, i_htfEmaLen), lookahead=barmerge.lookahead_off)\nhtfClose = request.security(syminfo.tickerid, i_htfTF, close[1], lookahead=barmerge.lookahead_off)\nhtfOpen  = request.security(syminfo.tickerid, i_htfTF, open[1],  lookahead=barmerge.lookahead_off)\n\nhtfEmaBull   = close > htfEma\nhtfEmaBear   = close < htfEma\nhtfCandleBull = htfClose > htfOpen   // last HTF candle was bullish\nhtfCandleBear = htfClose < htfOpen   // last HTF candle was bearish\n\n// Alignment gate\nhtfBullOK = not i_useHTF or (i_htfStrict ? (htfEmaBull and htfCandleBull) : htfEmaBull)\nhtfBearOK = not i_useHTF or (i_htfStrict ? (htfEmaBear and htfCandleBear) : htfEmaBear)\n\n// Plot HTF EMA\nplot(i_showHTFEma ? htfEma : na, \"HTF EMA\", color=htfEmaBull ? color.new(#00bcd4, 40) : color.new(#ff9800, 40), linewidth=2)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  TREND FILTER  \u2014  follows trading style\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// EMA pairs auto-selected by Trading Style:\n//   Scalping  \u2192  EMA 8  / EMA 21   (1m\u20135m charts)\n//   Intraday  \u2192  EMA 20 / EMA 50   (15m\u20131H charts)\n//   Swing     \u2192  EMA 50 / EMA 200  (4H\u2013Daily charts)\n// Override with custom values in inputs.\n\n// Resolve EMA lengths from style or custom override\nstyleDefault_fast = i_tradingStyle == \"Scalping\" ? 8  :\n                    i_tradingStyle == \"Swing\"    ? 50 : 20\nstyleDefault_slow = i_tradingStyle == \"Scalping\" ? 21  :\n                    i_tradingStyle == \"Swing\"    ? 200 : 50\n\ntrendFastLen = i_trendEmaFast > 0 ? i_trendEmaFast : styleDefault_fast\ntrendSlowLen = i_trendEmaSlow > 0 ? i_trendEmaSlow : styleDefault_slow\n\ntrendEmaFast = ta.ema(close, trendFastLen)\ntrendEmaSlow = ta.ema(close, trendSlowLen)\n\n// Trend direction\ntrendUp   = trendEmaFast > trendEmaSlow   // fast above slow \u2192 bullish trend\ntrendDown = trendEmaFast < trendEmaSlow   // fast below slow \u2192 bearish trend\n\n// Trend strength: slope of fast EMA (positive = rising, negative = falling)\ntrendSlope = trendEmaFast - trendEmaFast[3]\ntrendStrengthLbl = math.abs(trendSlope) > atr14 * 0.1 ? (trendUp ? \"Strong \u25b2\" : \"Strong \u25bc\") : (trendUp ? \"Weak \u25b2\" : \"Weak \u25bc\")\n\ntrendDirLbl = trendUp ? \"\u25b2 UP (\" + str.tostring(trendFastLen) + \">\" + str.tostring(trendSlowLen) + \")\" : trendDown ? \"\u25bc DOWN (\" + str.tostring(trendFastLen) + \"<\" + str.tostring(trendSlowLen) + \")\" : \"Ranging\"\ntrendDirBgc = trendUp ? color.new(#00e676, 30) : trendDown ? color.new(#ff1744, 30) : color.new(color.gray, 40)\n\n// Gate: only trade in trend direction\ntrendBullOK = not i_useTrend or trendUp\ntrendBearOK = not i_useTrend or trendDown\n\n// Plot trend EMAs on chart\nplot(i_showTrendEma ? trendEmaFast : na, \"Trend EMA Fast (\" + str.tostring(trendFastLen) + \")\", color=trendUp ? color.new(#00e676, 30) : color.new(#ff1744, 30), linewidth=1)\nplot(i_showTrendEma ? trendEmaSlow : na, \"Trend EMA Slow (\" + str.tostring(trendSlowLen) + \")\", color=trendUp ? color.new(#00e676, 55) : color.new(#ff1744, 55), linewidth=2)\n\n// Momentum bar coloring \u2014 bars adopt trend color inside kill zones\nbarcolor(i_useTrend and inKZ and trendUp   ? color.new(#00e676, 60) :\n         i_useTrend and inKZ and trendDown ? color.new(#ff1744, 60) : na,\n         title=\"Trend Momentum Bar Color\")\n\n// Trend Cloud\ntPlot1 = plot(i_showTrendEma ? trendEmaFast : na, color=na)\ntPlot2 = plot(i_showTrendEma ? trendEmaSlow : na, color=na)\nfill(tPlot1, tPlot2, color = trendUp ? color.new(i_bullCol, 88) : trendDown ? color.new(i_bearCol, 88) : na, title = \"Trend Cloud\")\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  CRT  3-CANDLE AMD PATTERN\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// Candles:\n//   C1 = bar_index[-2]  \u2192  Accumulation\n//   C2 = bar_index[-1]  \u2192  Manipulation (liquidity grab)\n//   C3 = bar_index[0]   \u2192  Distribution (signal bar, close confirms reversal)\n\nc1Hi   = high[2]\nc1Lo   = low[2]\nc1Mid  = (c1Hi + c1Lo) / 2\n\nc2Hi   = high[1]\nc2Lo   = low[1]\nc2Cls  = close[1]\nc2Opn  = open[1]\nc2Body_top = math.max(c2Cls, c2Opn)\nc2Body_bot = math.min(c2Cls, c2Opn)\n\n// \u2500\u2500 Manipulation detection \u2500\u2500\nc2WickAbove = c2Hi  > c1Hi\nc2WickBelow = c2Lo  < c1Lo\nc2BodyAbove = c2Body_top > c1Hi\nc2BodyBelow = c2Body_bot < c1Lo\n\n// Apply TBS filter\nbullManip = i_tbsOnly ? c2BodyBelow : c2WickBelow\nbearManip = i_tbsOnly ? c2BodyAbove : c2WickAbove\n\n// \u2500\u2500 C3 Distribution \u2500\u2500\nc3BullConfirm = close > c1Hi\nc3BearConfirm = close < c1Lo\n\n// \u2500\u2500 Raw CRT signals \u2500\u2500\ncrtBull = bullManip and c3BullConfirm\ncrtBear = bearManip and c3BearConfirm\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  VOLUME & STRUCTURE LOGIC\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nvolMA = ta.sma(volume, i_volMALen)\n// Volume Exhaustion: C2 volume should be higher than C1 and C3 should have healthy volume\nvolExhaustion = volume[1] > volMA[1] or volume[1] > volume[2]\nvolConfirm    = not i_volFilter or volExhaustion\n\n// Market Structure Shift (MSS) for C3\n// Bull MSS: Close > highest of C1 and C2\n// Bear MSS: Close < lowest of C1 and C2\nmssBull = close > math.max(c1Hi, c2Hi)\nmssBear = close < math.min(c1Lo, c2Lo)\nmssOK   = not i_mssFilter or (crtBull ? mssBull : crtBear ? mssBear : false)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  FINAL SIGNAL\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nbullSigSource = crtBull and inKZ and htfBullOK and trendBullOK and volConfirm and mssOK\nbullSig = bullSigSource and (i_showDir == \"Both\" or i_showDir == \"Bullish Only\")\n\nbearSigSource = crtBear and inKZ and htfBearOK and trendBearOK and volConfirm and mssOK\nbearSig = bearSigSource and (i_showDir == \"Both\" or i_showDir == \"Bearish Only\")\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  ENTRY / SL / TP LEVELS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n// \u2500\u2500 BULL levels \u2500\u2500\nbullEntry = i_entryAt == \"C1 Mid\"           ? c1Mid\n          : i_entryAt == \"C1 Opposite Edge\" ? c1Hi\n          : close   // C3 Close\n\nbullSL = i_slAt == \"C2 Extreme\"  ? c2Lo  * (1 - i_slBuf / 100)\n       : i_slAt == \"C1 Edge\"     ? c1Lo  * (1 - i_slBuf / 100)\n       : close - atr14 * i_atrSLMult\n\nbullRisk = math.max(math.abs(bullEntry - bullSL), syminfo.mintick)\nbullTP1  = bullEntry + bullRisk * i_tp1R\nbullTP2  = bullEntry + bullRisk * i_tp2R\n\n// \u2500\u2500 BEAR levels \u2500\u2500\nbearEntry = i_entryAt == \"C1 Mid\"           ? c1Mid\n          : i_entryAt == \"C1 Opposite Edge\" ? c1Lo\n          : close\n\nbearSL = i_slAt == \"C2 Extreme\"  ? c2Hi  * (1 + i_slBuf / 100)\n       : i_slAt == \"C1 Edge\"     ? c1Hi  * (1 + i_slBuf / 100)\n       : close + atr14 * i_atrSLMult\n\nbearRisk = math.max(math.abs(bearSL - bearEntry), syminfo.mintick)\nbearTP1  = bearEntry - bearRisk * i_tp1R\nbearTP2  = bearEntry - bearRisk * i_tp2R\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  SIGNAL ARROWS  (above/below bar)\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nplotshape(bullSig, title=\"CRT+TBS Bull\", location=location.belowbar, style=shape.triangleup, color=i_bullCol, size=size.large)\n\nplotshape(bearSig, title=\"CRT+TBS Bear\", location=location.abovebar, style=shape.triangledown, color=i_bearCol, size=size.large)\n\n// \u2500\u2500 Entry price dot AT exact price \u2500\u2500\nplotshape(bullSig ? bullEntry : na, title=\"Bull Entry Dot\", location=location.absolute, style=shape.circle, color=color.white, size=size.small)\nplotshape(bearSig ? bearEntry : na, title=\"Bear Entry Dot\", location=location.absolute, style=shape.circle, color=color.white, size=size.small)\n\n// \u2500\u2500 R:R level dots (plot at exact price) \u2500\u2500\nplot(bullSig ? bullSL  : na, \"Bull SL\",  style=plot.style_circles, color=i_bearCol, linewidth=5)\nplot(bullSig ? bullTP1 : na, \"Bull TP1\", style=plot.style_circles, color=i_bullCol, linewidth=5)\nplot(bullSig ? bullTP2 : na, \"Bull TP2\", style=plot.style_circles, color=color.new(i_bullCol,35), linewidth=4)\nplot(bearSig ? bearSL  : na, \"Bear SL\",  style=plot.style_circles, color=i_bearCol, linewidth=5)\nplot(bearSig ? bearTP1 : na, \"Bear TP1\", style=plot.style_circles, color=i_bullCol, linewidth=5)\nplot(bearSig ? bearTP2 : na, \"Bear TP2\", style=plot.style_circles, color=color.new(i_bullCol,35), linewidth=4)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  DRAW BOXES + ENTRY LINE + LABELS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nvar string lastSig  = \"\u2014\"\nvar int    sigCount = 0\n\n// \u2500\u2500 BULLISH \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nif bullSig\n    sigCount += 1\n    lastSig  := \"Bullish\"\n    B = bar_index\n    R = B + i_boxBars\n    rPts = math.round(bullRisk, syminfo.mintick > 0.001 ? 2 : 5)\n\n    // C1 accumulation range box\n    if i_showC1Box\n        box.new(B - 2, c1Hi, R, c1Lo, border_color=color.new(i_c1Col, 30), bgcolor=color.new(i_c1Col, 85), border_width=1)\n\n    // C2 manipulation marker (body or wick that swept below)\n    if i_showC2Mk\n        mLvl = i_tbsOnly ? c2Body_bot : c2Lo\n        line.new(B - 1, mLvl, B + 1, mLvl, color=color.new(i_bullCol, 20), width=2, style=line.style_dotted)\n        label.new(B - 1, mLvl, i_tbsOnly ? \"TBS\" : \"TWS\", style=label.style_label_right, color=color.new(i_bullCol, 30), textcolor=color.white, size=size.tiny)\n\n    // SL zone (below entry)\n    box.new(B, bullEntry, R, bullSL, border_color=color.new(i_bearCol, 30), bgcolor=color.new(i_bearCol, i_alpha))\n\n    // TP1 zone\n    box.new(B, bullTP1, R, bullEntry, border_color=color.new(i_bullCol, 30), bgcolor=color.new(i_bullCol, i_alpha))\n\n    // TP2 zone\n    box.new(B, bullTP2, R, bullTP1, border_color=color.new(i_bullCol, 55), bgcolor=color.new(i_bullCol, math.min(i_alpha + 10, 99)))\n\n    // ENTRY LINE \u2014 thick white, most prominent\n    line.new(B, bullEntry, R, bullEntry, color=color.white, width=3, style=line.style_solid)\n\n    // Entry label ON the line\n    label.new(B, bullEntry, \"\ud83c\udfaf BUY @ \" + f_price(bullEntry) + kzTag, xloc=xloc.bar_index, style=label.style_label_right, color=i_bullCol, textcolor=color.white, size=f_lsize(i_lblSize))\n\n    // SL line + label\n    line.new(B, bullSL, R, bullSL, color=i_bearCol, width=2, style=line.style_solid)\n    if i_showLabels\n        label.new(B, bullSL, \"\u2715 SL @ \" + f_price(bullSL), xloc=xloc.bar_index, style=label.style_label_right, color=color.new(i_bearCol, 20), textcolor=color.white, size=size.small)\n\n    // TP1 line + label\n    line.new(B, bullTP1, R, bullTP1, color=i_bullCol, width=2, style=line.style_solid)\n    if i_showLabels\n        label.new(B, bullTP1, \"\u2714 TP1 \" + str.tostring(i_tp1R) + \"R  @ \" + f_price(bullTP1), xloc=xloc.bar_index, style=label.style_label_right, color=color.new(i_bullCol, 20), textcolor=color.white, size=size.small)\n\n    // TP2 line + label\n    line.new(B, bullTP2, R, bullTP2, color=color.new(i_bullCol, 30), width=1, style=line.style_dashed)\n    if i_showLabels\n        label.new(B, bullTP2, \"\u2714 TP2 \" + str.tostring(i_tp2R) + \"R  @ \" + f_price(bullTP2), xloc=xloc.bar_index, style=label.style_label_right, color=color.new(i_bullCol, 45), textcolor=color.white, size=size.small)\n\n    // Risk summary label on right\n    if i_showLabels\n        label.new(R, (bullTP1 + bullEntry) / 2, \"LONG  |  Risk: \" + str.tostring(rPts) + \"  |  R:\" + str.tostring(i_tp1R) + \" / \" + str.tostring(i_tp2R), xloc=xloc.bar_index, style=label.style_label_left, color=color.new(i_bullCol, 25), textcolor=color.white, size=size.small)\n\n// \u2500\u2500 BEARISH \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nif bearSig\n    sigCount += 1\n    lastSig  := \"Bearish\"\n    B = bar_index\n    R = B + i_boxBars\n    rPts = math.round(bearRisk, syminfo.mintick > 0.001 ? 2 : 5)\n\n    // C1 accumulation range box\n    if i_showC1Box\n        box.new(B - 2, c1Hi, R, c1Lo, border_color=color.new(i_c1Col, 30), bgcolor=color.new(i_c1Col, 85), border_width=1)\n\n    // C2 manipulation marker\n    if i_showC2Mk\n        mLvl = i_tbsOnly ? c2Body_top : c2Hi\n        line.new(B - 1, mLvl, B + 1, mLvl, color=color.new(i_bearCol, 20), width=2, style=line.style_dotted)\n        label.new(B - 1, mLvl, i_tbsOnly ? \"TBS\" : \"TWS\", style=label.style_label_right, color=color.new(i_bearCol, 30), textcolor=color.white, size=size.tiny)\n\n    // SL zone (above entry)\n    box.new(B, bearSL, R, bearEntry, border_color=color.new(i_bearCol, 30), bgcolor=color.new(i_bearCol, i_alpha))\n\n    // TP1 zone\n    box.new(B, bearEntry, R, bearTP1, border_color=color.new(i_bullCol, 30), bgcolor=color.new(i_bullCol, i_alpha))\n\n    // TP2 zone\n    box.new(B, bearTP1, R, bearTP2, border_color=color.new(i_bullCol, 55), bgcolor=color.new(i_bullCol, math.min(i_alpha + 10, 99)))\n\n    // ENTRY LINE \u2014 thick white\n    line.new(B, bearEntry, R, bearEntry, color=color.white, width=3, style=line.style_solid)\n\n    // Entry label ON the line\n    label.new(B, bearEntry, \"\ud83c\udfaf SELL @ \" + f_price(bearEntry) + kzTag, xloc=xloc.bar_index, style=label.style_label_right, color=i_bearCol, textcolor=color.white, size=f_lsize(i_lblSize))\n\n    // SL line + label\n    line.new(B, bearSL, R, bearSL, color=i_bearCol, width=2, style=line.style_solid)\n    if i_showLabels\n        label.new(B, bearSL, \"\u2715 SL @ \" + f_price(bearSL), xloc=xloc.bar_index, style=label.style_label_right, color=color.new(i_bearCol, 20), textcolor=color.white, size=size.small)\n\n    // TP1 line + label\n    line.new(B, bearTP1, R, bearTP1, color=i_bullCol, width=2, style=line.style_solid)\n    if i_showLabels\n        label.new(B, bearTP1, \"\u2714 TP1 \" + str.tostring(i_tp1R) + \"R  @ \" + f_price(bearTP1), xloc=xloc.bar_index, style=label.style_label_right, color=color.new(i_bullCol, 20), textcolor=color.white, size=size.small)\n\n    // TP2 line + label\n    line.new(B, bearTP2, R, bearTP2, color=color.new(i_bullCol, 30), width=1, style=line.style_dashed)\n    if i_showLabels\n        label.new(B, bearTP2, \"\u2714 TP2 \" + str.tostring(i_tp2R) + \"R  @ \" + f_price(bearTP2), xloc=xloc.bar_index, style=label.style_label_right, color=color.new(i_bullCol, 45), textcolor=color.white, size=size.small)\n\n    // Risk summary label on right\n    if i_showLabels\n        label.new(R, (bearEntry + bearTP1) / 2, \"SHORT  |  Risk: \" + str.tostring(rPts) + \"  |  R:\" + str.tostring(i_tp1R) + \" / \" + str.tostring(i_tp2R), xloc=xloc.bar_index, style=label.style_label_left, color=color.new(i_bearCol, 25), textcolor=color.white, size=size.small)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  DASHBOARD\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nvar table dash = table.new(position.top_right, 2, 15, border_width=1, border_color=color.new(color.gray, 50), bgcolor=color.new(#0d1117, 8))\n\nif i_showDash and barstate.islast\n    hCol = color.new(#1565c0, 15)\n    table.cell(dash, 0, 0, \"CRT + TBS\", text_color=color.white, bgcolor=hCol, text_size=size.normal, text_halign=text.align_center)\n    table.cell(dash, 1, 0, \"Turtle Body Soup\", text_color=color.white, bgcolor=hCol, text_size=size.normal, text_halign=text.align_center)\n\n    // Kill Zone\n    kzLbl = inKZ ? kzTag + \" ACTIVE\" : \"No Kill Zone\"\n    kzCol = inKZ ? color.new(#ffa726, 20) : color.new(color.gray, 55)\n    table.cell(dash, 0, 1, \"Session\", text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 1, kzLbl,    text_color=color.white, bgcolor=kzCol)\n\n    // ET Hour\n    table.cell(dash, 0, 2, \"ET Hour\", text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 2, str.tostring(etH) + \":xx ET\",\n         text_color=color.white, bgcolor=color.new(color.gray, 50))\n\n    // CRT pattern\n    crtLbl = crtBull ? \"\u2b06 Bull CRT\" : crtBear ? \"\u2b07 Bear CRT\" : \"Scanning...\"\n    crtBgc = crtBull ? color.new(#00e676, 35) : crtBear ? color.new(#ff1744, 35) : color.new(color.gray, 55)\n    table.cell(dash, 0, 3, \"CRT Pattern\", text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 3, crtLbl,        text_color=color.white, bgcolor=crtBgc)\n\n    // TBS confirmation\n    tbsBull = c2BodyBelow\n    tbsBear = c2BodyAbove\n    tbsLbl  = tbsBull ? \"\u2b06 Bull TBS (body)\" : tbsBear ? \"\u2b07 Bear TBS (body)\" : \"No TBS\"\n    tbsBgc  = tbsBull ? color.new(#00e676, 35) : tbsBear ? color.new(#ff1744, 35) : color.new(color.gray, 55)\n    table.cell(dash, 0, 4, \"TBS (body close)\",  text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 4, tbsLbl,              text_color=color.white, bgcolor=tbsBgc)\n\n    // C2 wick sweep\n    wkLbl = c2WickBelow ? \"\u2193 Wick below C1\" : c2WickAbove ? \"\u2191 Wick above C1\" : \"No sweep\"\n    wkBgc = c2WickBelow ? color.new(#00e676, 50) : c2WickAbove ? color.new(#ff1744, 50) : color.new(color.gray, 55)\n    table.cell(dash, 0, 5, \"C2 Wick Sweep\",  text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 5, wkLbl,            text_color=color.white, bgcolor=wkBgc)\n\n    // HTF\n    htfLbl = htfEmaBull ? \"\u25b2 Bull (above EMA)\" : htfEmaBear ? \"\u25bc Bear (below EMA)\" : \"Neutral\"\n    htfBgc = htfEmaBull ? color.new(#00e676, 35) : htfEmaBear ? color.new(#ff1744, 35) : color.new(color.gray, 35)\n    table.cell(dash, 0, 6, \"HTF Bias\", text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 6, htfLbl,     text_color=color.white, bgcolor=htfBgc)\n\n    // HTF Candle structure\n    hcLbl = htfCandleBull ? \"\u25b2 Last 1H Bullish\" : htfCandleBear ? \"\u25bc Last 1H Bearish\" : \"Doji\"\n    hcBgc = htfCandleBull ? color.new(#00e676, 45) : htfCandleBear ? color.new(#ff1744, 45) : color.new(color.gray, 45)\n    table.cell(dash, 0, 7, \"HTF Candle\",  text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 7, hcLbl,         text_color=color.white, bgcolor=hcBgc)\n\n    // Trend style\n    table.cell(dash, 0, 8, \"Trading Style\",   text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 8, i_tradingStyle + (i_useTrend ? \"  ON\" : \"  OFF\"),\n         text_color=color.white, bgcolor=color.new(color.gray, 50))\n\n    // Trend direction\n    table.cell(dash, 0, 9,  \"Trend\",  text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 9,  trendDirLbl, text_color=color.white, bgcolor=trendDirBgc)\n\n    table.cell(dash, 0, 11, \"Volume/MSS\", text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 11, (i_volFilter ? (volExhaustion ? \"Vol \u2705\" : \"Vol \u274c\") : \"Vol \u2014\") + \" | \" + (i_mssFilter ? (mssOK ? \"MSS \u2705\" : \"MSS \u274c\") : \"MSS \u2014\"), text_color=color.white, bgcolor=(volExhaustion or not i_volFilter) ? color.new(#00e676, 45) : color.new(#ff1744, 45))\n    table.cell(dash, 0, 12, \"Entry / SL\", text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 12, i_entryAt + \" / \" + i_slAt, text_color=color.white, bgcolor=color.new(color.gray, 50))\n    sigClr = lastSig == \"Bullish\" ? color.new(#00e676, 25) : lastSig == \"Bearish\" ? color.new(#ff1744, 25) : color.new(color.gray, 50)\n    table.cell(dash, 0, 13, \"Last Signal\", text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 13, lastSig, text_color=color.white, bgcolor=sigClr)\n    table.cell(dash, 0, 14, \"Total Signals\", text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 14, str.tostring(sigCount), text_color=color.white, bgcolor=color.new(color.gray, 50))\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  ALERTS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nalertcondition(bullSig, title=\"CRT+TBS BUY Signal\", message=\"\ud83d\udfe2 CRT+TBS BUY | {{ticker}} @ {{close}} | Kill Zone + TBS body close + HTF aligned\")\nalertcondition(bearSig, title=\"CRT+TBS SELL Signal\", message=\"\ud83d\udd34 CRT+TBS SELL | {{ticker}} @ {{close}} | Kill Zone + TBS body close + HTF aligned\")\nalertcondition(bullSig or bearSig, title=\"CRT+TBS Any Signal\", message=\"\u26a1 CRT+TBS Signal | {{ticker}} @ {{close}} | Full confluence confirmed\")\nalertcondition(crtBull and inKZ, title=\"CRT Bull (no HTF gate)\", message=\"\ud83d\udcca CRT Bull pattern in Kill Zone | {{ticker}} @ {{close}}\")\nalertcondition(crtBear and inKZ, title=\"CRT Bear (no HTF gate)\", message=\"\ud83d\udcca CRT Bear pattern in Kill Zone | {{ticker}} @ {{close}}\")"
  },
  {
    "id": "sweep_crt.pine",
    "name": "HTF FVG + Entry TF Reversal FVG",
    "code": "//@version=5\nindicator(\"HTF FVG + Entry TF Reversal FVG\", shorttitle=\"HTF\u00b7FVG\u00b7Entry\", overlay=true, max_labels_count = 500, max_lines_count  = 500, max_boxes_count  = 500)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// TRADING STYLE\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ngrp_style = \"\ud83c\udfaf Trading Style\"\nstyle = input.string(\"Intraday\", \"Style Preset\", options=[\"Scalper\", \"Intraday\", \"Swing\", \"Position\"], group=grp_style, tooltip=\"Sets HTF, Entry TF suggestions, RR, and SL automatically.\")\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// HTF + ENTRY TF PER STYLE\n// Scalper  : HTF=15M,  Entry=1M\u20133M\n// Intraday : HTF=1H/4H, Entry=5M\u201315M\n// Swing    : HTF=4H/D,  Entry=1H\n// Position : HTF=W,     Entry=D\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ngrp_tf = \"\u23f1 Timeframe Settings\"\n\nhtf_tf = input.timeframe(\"60\", \"HTF Timeframe (FVG Source)\", group=grp_tf, tooltip=\"Scalper\u219215 | Intraday\u219260 or 240 | Swing\u2192240 or D | Position\u2192W\")\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// FVG SETTINGS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ngrp_fvg = \"\u26a1 FVG Settings\"\n\nfvg_min_pct = input.float(0.0, \"Min FVG Size (points, 0=any)\", minval=0.0, step=0.1, group=grp_fvg, tooltip=\"Set to 0 to catch all FVGs. Increase to filter tiny gaps. For Gold use 0.5\u20132.0\")\n\nshow_htf_fvg   = input.bool(true,  \"Show HTF FVG Zones\",             group=grp_fvg)\nshow_entry_fvg = input.bool(true,  \"Show Entry TF Reversal FVG\",     group=grp_fvg)\nhtf_fvg_extend = input.bool(true,  \"Extend HTF FVG Until Mitigated\", group=grp_fvg)\nmax_htf_fvg    = input.int(5, \"Max HTF FVGs on Chart\", minval=1, maxval=20, group=grp_fvg)\n\n// How deep into the FVG price must reach before\n// the reversal FVG is valid (0=just touch, 1=full)\nfvg_respect_depth = input.float(0.5, \"FVG Respect Depth (0\u20131)\", minval=0.0, maxval=1.0, step=0.1, group=grp_fvg, tooltip=\"0 = price just touches FVG edge to trigger\\n0.5 = price reaches midpoint\\n1.0 = price fills entire FVG\\nLower = more signals, higher = stronger confirmation\")\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// RR SETTINGS \u2014 Auto by style, manual override\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ngrp_rr = \"\ud83c\udfaf RR Settings\"\n\nauto_rr = input.bool(true, \"Auto RR from Style Preset\", group=grp_rr)\nman_rr       = input.float(2.0, \"Manual RR Ratio\",    minval=1.0, maxval=10.0, step=0.5, group=grp_rr)\nman_sl_mult  = input.float(0.5, \"Manual SL ATR Mult\", minval=0.1, maxval=5.0,  step=0.1, group=grp_rr)\nman_box_w    = input.int(30,    \"Manual Box Width\",   minval=5,   maxval=300,  step=5,   group=grp_rr)\n\npreset_rr_val = style == \"Scalper\" ? 1.5 : style == \"Intraday\" ? 2.0 : style == \"Swing\" ? 3.0 : 4.0\n\npreset_sl_val = style == \"Scalper\" ? 0.3 : style == \"Intraday\" ? 0.5 : style == \"Swing\" ? 1.0 : 1.5\n\npreset_bw_val = style == \"Scalper\" ? 15 : style == \"Intraday\" ? 30 : style == \"Swing\" ? 60 : 100\n\nf_rr    = auto_rr ? preset_rr_val : man_rr\nf_sl    = auto_rr ? preset_sl_val : man_sl_mult\nf_bw    = auto_rr ? preset_bw_val : man_box_w\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// COLORS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ngrp_col = \"\ud83c\udfa8 Colors\"\nbull_htf_col  = input.color(color.new(#00E676, 82), \"HTF Bull FVG\",      group=grp_col)\nbear_htf_col  = input.color(color.new(#FF1744, 82), \"HTF Bear FVG\",      group=grp_col)\nbull_rev_col  = input.color(color.new(#00BCD4, 75), \"Entry Bull Rev FVG\",group=grp_col)\nbear_rev_col  = input.color(color.new(#FF9800, 75), \"Entry Bear Rev FVG\",group=grp_col)\ntp_col        = input.color(color.new(#80CBC4, 45), \"TP Box\",            group=grp_col)\nsl_col        = input.color(color.new(#F48FB1, 45), \"SL Box\",            group=grp_col)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// UTILITY\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\natr14 = ta.atr(14)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// HTF DATA FETCH\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n[htf_h0, htf_h1, htf_h2] = request.security(syminfo.tickerid, htf_tf, [high[0], high[1], high[2]], lookahead=barmerge.lookahead_off)\n[htf_l0, htf_l1, htf_l2] = request.security(syminfo.tickerid, htf_tf, [low[0], low[1], low[2]], lookahead=barmerge.lookahead_off)\n[htf_c0, htf_c1] = request.security(syminfo.tickerid, htf_tf, [close[0], close[1]], lookahead=barmerge.lookahead_off)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// HTF FVG DETECTION\n// Bull FVG: candle[2] high < candle[0] low \u2014 upward gap\n// Bear FVG: candle[2] low  > candle[0] high \u2014 downward gap\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nhtf_bull_fvg = htf_l0 > htf_h2 and (htf_l0 - htf_h2) >= fvg_min_pct\nhtf_bear_fvg = htf_h0 < htf_l2 and (htf_l2 - htf_h0) >= fvg_min_pct\n\nhtf_bull_fvg_top = htf_l0\nhtf_bull_fvg_bot = htf_h2\nhtf_bear_fvg_top = htf_l2\nhtf_bear_fvg_bot = htf_h0\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// HTF FVG ZONE STORAGE + DRAWING\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nvar float[] fvg_top     = array.new_float()\nvar float[] fvg_bot     = array.new_float()\nvar bool[]  fvg_bull    = array.new_bool()\nvar bool[]  fvg_active  = array.new_bool()\nvar box[]   fvg_box_arr = array.new_box()\nvar int[]   fvg_bar_arr = array.new_int()\n\nf_add_fvg(top, bot, is_bull) =>\n    // Trim if over max\n    if array.size(fvg_top) >= max_htf_fvg\n        old_box = array.shift(fvg_box_arr)\n        box.delete(old_box)\n        array.shift(fvg_top)\n        array.shift(fvg_bot)\n        array.shift(fvg_bull)\n        array.shift(fvg_active)\n        array.shift(fvg_bar_arr)\n\n    bg = is_bull ? bull_htf_col : bear_htf_col\n    bc = is_bull ? color.new(#00E676, 50) : color.new(#FF1744, 50)\n    b  = box.new(bar_index, top, bar_index + 500, bot, border_color=bc, border_width=1, bgcolor=bg)\n\n    // Midpoint label\n    mid   = (top + bot) / 2\n    tag   = is_bull ? \"\u25b2 HTF Bull FVG\" : \"\u25bc HTF Bear FVG\"\n    tcol  = is_bull ? color.new(#00E676, 0) : color.new(#FF1744, 0)\n    bgcol = is_bull ? color.new(#0B3D1A, 0) : color.new(#3D0B0B, 0)\n    label.new(bar_index, top, tag + \" [\" + htf_tf + \"M]  \" + str.tostring(math.round(bot, 2)) + \"\u2013\" + str.tostring(math.round(top, 2)), color=bgcol, textcolor=tcol, style=label.style_label_right, size=size.tiny)\n\n    array.push(fvg_top,     top)\n    array.push(fvg_bot,     bot)\n    array.push(fvg_bull,    is_bull)\n    array.push(fvg_active,  true)\n    array.push(fvg_box_arr, b)\n    array.push(fvg_bar_arr, bar_index)\n\n// Add new FVGs\nif htf_bull_fvg\n    f_add_fvg(htf_bull_fvg_top, htf_bull_fvg_bot, true)\n\nif htf_bear_fvg\n    f_add_fvg(htf_bear_fvg_top, htf_bear_fvg_bot, false)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// TRACK WHICH HTF FVG PRICE IS RESPECTING\n// \"Respect\" = price wicked INTO the FVG zone\n// but has NOT fully closed through it\n// This is the \"price touched FVG\" condition\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nvar bool in_bull_fvg  = false\nvar bool in_bear_fvg  = false\nvar float active_bull_fvg_top = na\nvar float active_bull_fvg_bot = na\nvar float active_bear_fvg_top = na\nvar float active_bear_fvg_bot = na\n\nin_bull_fvg  := false\nin_bear_fvg  := false\n\nif array.size(fvg_top) > 0\n    for i = array.size(fvg_top) - 1 to 0\n        if array.get(fvg_active, i)\n            top     = array.get(fvg_top, i)\n            bot     = array.get(fvg_bot, i)\n            is_bull = array.get(fvg_bull, i)\n            fvg_mid = bot + (top - bot) * fvg_respect_depth\n\n            // Bull FVG: price wicks down into zone\n            // Respect = low touched zone, close still above bot\n            if is_bull\n                if low <= top and low >= bot and close > fvg_mid\n                    in_bull_fvg          := true\n                    active_bull_fvg_top  := top\n                    active_bull_fvg_bot  := bot\n                    // Shade box to show it's being respected\n                    box.set_bgcolor(array.get(fvg_box_arr, i),\n                         color.new(#00E676, 70))\n\n                // Fully mitigated \u2014 price closed below the FVG\n                if close < bot\n                    array.set(fvg_active, i, false)\n                    box.set_bgcolor(array.get(fvg_box_arr, i),\n                         color.new(#00E676, 94))\n                    if htf_fvg_extend\n                        box.set_right(array.get(fvg_box_arr, i), bar_index)\n\n            // Bear FVG: price wicks up into zone\n            if not is_bull\n                if high >= bot and high <= top and close < fvg_mid\n                    in_bear_fvg          := true\n                    active_bear_fvg_top  := top\n                    active_bear_fvg_bot  := bot\n                    box.set_bgcolor(array.get(fvg_box_arr, i),\n                         color.new(#FF1744, 70))\n\n                if close > top\n                    array.set(fvg_active, i, false)\n                    box.set_bgcolor(array.get(fvg_box_arr, i),\n                         color.new(#FF1744, 94))\n                    if htf_fvg_extend\n                        box.set_right(array.get(fvg_box_arr, i), bar_index)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// ENTRY TF REVERSAL FVG DETECTION\n// After price respects HTF FVG, look for\n// an immediate FVG in the opposite direction\n// on the current (entry) timeframe\n//\n// Bull reversal FVG (inside bull HTF FVG):\n//   Candle[2] high < Candle[0] low\n//   AND current candle is bullish\n//   AND formed while price is in the bull FVG\n//\n// Bear reversal FVG (inside bear HTF FVG):\n//   Candle[2] low > Candle[0] high\n//   AND current candle is bearish\n//   AND formed while price is in the bear FVG\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nentry_bull_fvg_top = low[0]\nentry_bull_fvg_bot = high[2]\nentry_bull_fvg_ok  = entry_bull_fvg_top > entry_bull_fvg_bot and\n                     close > open and\n                     (entry_bull_fvg_top - entry_bull_fvg_bot) >= fvg_min_pct\n\nentry_bear_fvg_top = low[2]\nentry_bear_fvg_bot = high[0]\nentry_bear_fvg_ok  = entry_bear_fvg_top > entry_bear_fvg_bot and\n                     close < open and\n                     (entry_bear_fvg_top - entry_bear_fvg_bot) >= fvg_min_pct\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// FINAL SIGNAL\n// HTF FVG respected + Entry TF reversal FVG\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfinal_bull = in_bull_fvg and entry_bull_fvg_ok\nfinal_bear = in_bear_fvg and entry_bear_fvg_ok\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// DRAW ENTRY REVERSAL FVG BOX\n// Small box showing where the reversal FVG formed\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nif show_entry_fvg and final_bull\n    box.new(bar_index - 2, entry_bull_fvg_top, bar_index, entry_bull_fvg_bot, border_color=color.new(#00BCD4, 20), border_width=1, bgcolor=bull_rev_col)\n    label.new(bar_index - 1, entry_bull_fvg_top, \"Rev FVG\", color=color.new(#00BCD4, 0), textcolor=color.white, style=label.style_label_up, size=size.tiny)\n\nif show_entry_fvg and final_bear\n    box.new(bar_index - 2, entry_bear_fvg_top, bar_index, entry_bear_fvg_bot, border_color=color.new(#FF9800, 20), border_width=1, bgcolor=bear_rev_col)\n    label.new(bar_index - 1, entry_bear_fvg_bot, \"Rev FVG\", color=color.new(#FF9800, 0), textcolor=color.white, style=label.style_label_down, size=size.tiny)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// RR BOX \u2014 Clean teal/pink style\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nif final_bull\n    entry  = close\n    sl     = entry - atr14 * f_sl\n    tp     = entry + (entry - sl) * f_rr\n    risk   = entry - sl\n    rr_act = risk > 0 ? (tp - entry) / risk : f_rr\n\n    box.new(bar_index, tp, bar_index + f_bw, entry, border_color=color.new(#80CBC4, 10), border_width=1, bgcolor=tp_col)\n    box.new(bar_index, entry, bar_index + f_bw, sl, border_color=color.new(#F48FB1, 10), border_width=1, bgcolor=sl_col)\n    line.new(bar_index, entry, bar_index + f_bw, entry, color=color.new(#ECEFF1, 30), width=2)\n    label.new(bar_index + f_bw, tp, \"  TP  \" + str.tostring(math.round(tp, 2)) + \"   \" + str.tostring(math.round(rr_act, 1)) + \"R\", color=color.new(#0B3D35, 0), textcolor=color.new(#80CBC4, 0), style=label.style_label_left, size=size.small)\n    label.new(bar_index + f_bw, entry, \"  ENTRY  \" + str.tostring(math.round(entry, 2)), color=color.new(#1C2833, 0), textcolor=color.new(#ECEFF1, 0), style=label.style_label_left, size=size.small)\n    label.new(bar_index + f_bw, sl, \"  SL  \" + str.tostring(math.round(sl, 2)), color=color.new(#3D0B1A, 0), textcolor=color.new(#F48FB1, 0), style=label.style_label_left, size=size.small)\n    label.new(bar_index, low - atr14 * 1.2, \"\u25b2 BUY  [\" + style + \" \u00b7 HTF:\" + htf_tf + \"]\", color=color.new(#00E676, 0), textcolor=color.white, style=label.style_label_up, size=size.normal)\n\nif final_bear\n    entry  = close\n    sl     = entry + atr14 * f_sl\n    tp     = entry - (sl - entry) * f_rr\n    risk   = sl    - entry\n    rr_act = risk > 0 ? (entry - tp) / risk : f_rr\n\n    box.new(bar_index, entry, bar_index + f_bw, tp, border_color=color.new(#80CBC4, 10), border_width=1, bgcolor=tp_col)\n    box.new(bar_index, sl, bar_index + f_bw, entry, border_color=color.new(#F48FB1, 10), border_width=1, bgcolor=sl_col)\n    line.new(bar_index, entry, bar_index + f_bw, entry, color=color.new(#ECEFF1, 30), width=2)\n    label.new(bar_index + f_bw, sl, \"  SL  \" + str.tostring(math.round(sl, 2)), color=color.new(#3D0B1A, 0), textcolor=color.new(#F48FB1, 0), style=label.style_label_left, size=size.small)\n    label.new(bar_index + f_bw, entry, \"  ENTRY  \" + str.tostring(math.round(entry, 2)), color=color.new(#1C2833, 0), textcolor=color.new(#ECEFF1, 0), style=label.style_label_left, size=size.small)\n    label.new(bar_index + f_bw, tp, \"  TP  \" + str.tostring(math.round(tp, 2)) + \"   \" + str.tostring(math.round(rr_act, 1)) + \"R\", color=color.new(#0B3D35, 0), textcolor=color.new(#80CBC4, 0), style=label.style_label_left, size=size.small)\n    label.new(bar_index, high + atr14 * 1.2, \"\u25bc SELL  [\" + style + \" \u00b7 HTF:\" + htf_tf + \"]\", color=color.new(#FF1744, 0), textcolor=color.white, style=label.style_label_down, size=size.normal)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// ALERTS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nalertcondition(final_bull, title=\"HTF FVG BUY\", message=\"\ud83d\udfe2 HTF FVG + Rev FVG BUY | {{ticker}} | {{interval}} | {{close}}\")\nalertcondition(final_bear, title=\"HTF FVG SELL\", message=\"\ud83d\udd34 HTF FVG + Rev FVG SELL | {{ticker}} | {{interval}} | {{close}}\")\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// DASHBOARD\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nvar table dash = table.new(position.top_right, 2, 10, bgcolor=#0D1117, border_color=color.new(#80CBC4, 40), border_width=1, frame_color=color.new(#80CBC4, 20), frame_width=2)\n\nif barstate.islast\n    table.cell(dash, 0, 0, \"HTF FVG + Rev FVG\", text_color=#80CBC4, text_size=size.small, bgcolor=#161B22, text_halign=text.align_center)\n    table.cell(dash, 1, 0, style, text_color=#FFA726, text_size=size.small, bgcolor=#161B22, text_halign=text.align_center)\n    table.cell(dash, 0, 1, \"HTF TF\",       text_color=color.silver, text_size=size.tiny)\n    table.cell(dash, 1, 1, htf_tf,         text_color=#FFA726,      text_size=size.tiny)\n    table.cell(dash, 0, 2, \"RR\",           text_color=color.silver, text_size=size.tiny)\n    table.cell(dash, 1, 2, str.tostring(f_rr) + \"R\", text_color=#80CBC4, text_size=size.tiny)\n    table.cell(dash, 0, 3, \"SL\",           text_color=color.silver, text_size=size.tiny)\n    table.cell(dash, 1, 3, str.tostring(f_sl) + \"\u00d7 ATR\", text_color=#80CBC4, text_size=size.tiny)\n    table.cell(dash, 0, 4, \"Active FVGs\",  text_color=color.silver, text_size=size.tiny)\n    table.cell(dash, 1, 4, str.tostring(array.size(fvg_top)), text_color=#FFA726, text_size=size.tiny)\n    table.cell(dash, 0, 5, \"In Bull FVG\",  text_color=color.silver, text_size=size.tiny)\n    table.cell(dash, 1, 5, in_bull_fvg ? \"\u2705 YES\" : \"\u2014\", text_color=in_bull_fvg ? #00E676 : color.gray, text_size=size.tiny)\n    table.cell(dash, 0, 6, \"In Bear FVG\",  text_color=color.silver, text_size=size.tiny)\n    table.cell(dash, 1, 6, in_bear_fvg ? \"\u2705 YES\" : \"\u2014\", text_color=in_bear_fvg ? #FF1744 : color.gray, text_size=size.tiny)\n    table.cell(dash, 0, 7, \"Rev Bull FVG\", text_color=color.silver, text_size=size.tiny)\n    table.cell(dash, 1, 7, entry_bull_fvg_ok ? \"\u2705 FORMED\" : \"\u2014\", text_color=entry_bull_fvg_ok ? #00BCD4 : color.gray, text_size=size.tiny)\n    table.cell(dash, 0, 8, \"Rev Bear FVG\", text_color=color.silver, text_size=size.tiny)\n    table.cell(dash, 1, 8, entry_bear_fvg_ok ? \"\u2705 FORMED\" : \"\u2014\", text_color=entry_bear_fvg_ok ? #FF9800 : color.gray, text_size=size.tiny)\n    table.cell(dash, 0, 9, \"\u25b6 SIGNAL\",    text_color=#80CBC4, text_size=size.tiny, bgcolor=#161B22)\n    table.cell(dash, 1, 9, final_bull ? \"\u25b2 BUY\" : final_bear ? \"\u25bc SELL\" : \"\u2014 Waiting \u2014\", text_color=final_bull ? #00E676 : final_bear ? #FF1744 : color.gray, text_size=size.small, bgcolor=#161B22)"
  },
  {
    "id": "scaping.pine",
    "name": "Scalping Strategy [KZ \u2192 Sweep \u2192 FVG + OB]",
    "code": "// ============================================================\n// SCALPING STRATEGY  |  Pine Script v5\n// ICT / SMC  \u2013  Kill Zone  \u2192  Sweep  \u2192  FVG + OB  \u2192  Entry\n// Optimised for 1m / 3m / 5m charts\n// ============================================================\n//@version=5\nindicator(\"Scalping Strategy [KZ \u2192 Sweep \u2192 FVG + OB]\",\n     shorttitle = \"SCALP PRO\",\n     overlay    = true,\n     max_lines_count  = 500,\n     max_boxes_count  = 500,\n     max_labels_count = 500)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  INPUTS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\ngrp_kz = \"\u2550\u2550\u2550  Kill Zones (UTC)  \u2550\u2550\u2550\"\ni_useLondon  = input.bool(true, \"London Kill Zone\",    group=grp_kz)\ni_lonStart   = input.int (6,  \"London  Start (UTC h)\", minval=0, maxval=23, group=grp_kz,\n     tooltip=\"London Open Kill Zone. Default 06:00\u201309:00 UTC.\")\ni_lonEnd     = input.int (9,  \"London  End   (UTC h)\", minval=0, maxval=23, group=grp_kz)\ni_useNY      = input.bool(true, \"New York Kill Zone\",  group=grp_kz)\ni_nyStart    = input.int (12, \"New York Start (UTC h)\", minval=0, maxval=23, group=grp_kz,\n     tooltip=\"New York Open Kill Zone. Default 12:00\u201315:00 UTC.\")\ni_nyEnd      = input.int (15, \"New York End   (UTC h)\", minval=0, maxval=23, group=grp_kz)\ni_useAsia    = input.bool(false, \"Asia Kill Zone\",     group=grp_kz)\ni_asiaStart  = input.int (0,  \"Asia    Start (UTC h)\", minval=0, maxval=23, group=grp_kz,\n     tooltip=\"Asia Kill Zone. Default 00:00\u201303:00 UTC.\")\ni_asiaEnd    = input.int (3,  \"Asia    End   (UTC h)\", minval=0, maxval=23, group=grp_kz)\n\ngrp_liq = \"\u2550\u2550\u2550  Liquidity Sweep  \u2550\u2550\u2550\"\ni_pivLen   = input.int  (3,   \"Pivot Length (bars each side)\", minval=1, maxval=10, group=grp_liq)\ni_sweepWin = input.int  (8,   \"Sweep Memory (bars)\",           minval=2, maxval=30,  group=grp_liq,\n     tooltip=\"Bars after sweep to still look for FVG entry.\")\ni_sweepBuf = input.float(0.0, \"Sweep Buffer (%)\",              minval=0.0, step=0.01, group=grp_liq,\n     tooltip=\"Min pierce beyond the pivot before it counts as a sweep.\")\ni_showSwMk = input.bool(true, \"Show Sweep Markers\",            group=grp_liq)\n\ngrp_fvg = \"\u2550\u2550\u2550  FVG Entry  \u2550\u2550\u2550\"\ni_minGap   = input.float(0.03, \"Min FVG Size (%)\", minval=0.0, step=0.01, group=grp_fvg,\n     tooltip=\"Minimum gap width as % of price. Lower for tight scalping.\")\ni_fvgRetrace = input.bool(true, \"Require Retrace into FVG\",   group=grp_fvg,\n     tooltip=\"Signal only when current bar retraces back into the FVG zone (tighter filter).\")\n\ngrp_ob = \"\u2550\u2550\u2550  Order Block  \u2550\u2550\u2550\"\ni_useOB    = input.bool(true, \"Require Order Block Confluence\", group=grp_ob,\n     tooltip=\"Only signal when an Order Block aligns with the FVG zone.\")\ni_obLookback = input.int(20,  \"OB Lookback (bars)\",            minval=5, maxval=50, group=grp_ob)\n\ngrp_ema = \"\u2550\u2550\u2550  Trend Filter  \u2550\u2550\u2550\"\ni_useTrend = input.bool(true, \"Use EMA Trend Filter\", group=grp_ema)\ni_emaFast  = input.int (8,   \"Fast EMA\",              minval=1,  group=grp_ema)\ni_emaSlow  = input.int (21,  \"Slow EMA\",              minval=2,  group=grp_ema)\ni_ema200   = input.int (200, \"Bias EMA\",              minval=50, group=grp_ema,\n     tooltip=\"Trade LONG only above this EMA, SHORT only below.\")\n\ngrp_rr = \"\u2550\u2550\u2550  Risk / Reward  \u2550\u2550\u2550\"\ni_dir       = input.string(\"Both\", \"Direction Filter\",\n     options=[\"Both\",\"Long Only\",\"Short Only\"], group=grp_rr)\ni_entryMode = input.string(\"FVG Mid\", \"Entry At\",\n     options=[\"FVG Mid\",\"FVG Edge\",\"Close\"], group=grp_rr)\ni_slMode    = input.string(\"OB Edge\", \"Stop-Loss At\",\n     options=[\"OB Edge\",\"Gap Edge\",\"Pivot\",\"Lookback\"], group=grp_rr)\ni_slLkb     = input.int  (5,   \"SL Lookback (bars)\", minval=1, maxval=30, group=grp_rr)\ni_slBuf     = input.float(0.1, \"SL Buffer (%)\",      minval=0.0, step=0.05, group=grp_rr)\ni_tp1       = input.float(1.5, \"TP1 R:R\",            minval=0.1, step=0.1,  group=grp_rr)\ni_tp2       = input.float(3.0, \"TP2 R:R\",            minval=0.1, step=0.1,  group=grp_rr)\n\ngrp_vis = \"\u2550\u2550\u2550  Visuals  \u2550\u2550\u2550\"\ni_extBars   = input.int  (50,  \"Box Extend Right (bars)\", minval=5, maxval=500, group=grp_vis)\ni_bullCol   = input.color(color.new(#00e676, 0),  \"Bullish Color\", group=grp_vis)\ni_bearCol   = input.color(color.new(#ff1744, 0),  \"Bearish Color\", group=grp_vis)\ni_obCol     = input.color(color.new(#ff9800, 0),  \"OB Color\",      group=grp_vis)\ni_alpha     = input.int  (80,  \"Box Transparency\",        minval=0, maxval=99, group=grp_vis)\ni_showFVG   = input.bool (true, \"Shade FVG Zone\",         group=grp_vis)\ni_showOB    = input.bool (true, \"Shade Order Block Zone\", group=grp_vis)\ni_showLabels= input.bool (true, \"Show Labels\",            group=grp_vis)\ni_showDash  = input.bool (true, \"Show Dashboard\",         group=grp_vis)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  KILL ZONE GATE\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nutcH = hour(time, \"UTC\")\n\ninLondon = i_useLondon and utcH >= i_lonStart   and utcH < i_lonEnd\ninNY     = i_useNY     and utcH >= i_nyStart     and utcH < i_nyEnd\ninAsiaKZ = i_useAsia   and utcH >= i_asiaStart   and utcH < i_asiaEnd\ninKZ     = inLondon or inNY or inAsiaKZ\n\nkzCol = inLondon ? color.new(#1565c0, 91) : inNY ? color.new(#1b5e20, 91) : inAsiaKZ ? color.new(#4a148c, 91) : na\nbgcolor(inKZ ? kzCol : na, title=\"Kill Zone Background\")\n\n// Kill zone label on first bar of each session\nkzName = inLondon ? \"LONDON KZ\" : inNY ? \"NEW YORK KZ\" : inAsiaKZ ? \"ASIA KZ\" : \"\"\nvar string prevKZ = \"\"\nif inKZ and kzName != prevKZ\n    label.new(bar_index, high, kzName, style=label.style_label_down,\n         color=color.new(#263238, 20), textcolor=color.white, size=size.tiny)\n    prevKZ := kzName\nif not inKZ\n    prevKZ := \"\"\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  TREND / BIAS  (EMA filter)\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nemaFast  = ta.ema(close, i_emaFast)\nemaSlow  = ta.ema(close, i_emaSlow)\nemaBias  = ta.ema(close, i_ema200)\n\nbullBias = close > emaBias\nbearBias = close < emaBias\ntrendUp  = emaFast > emaSlow\ntrendDn  = emaFast < emaSlow\n\nplot(emaFast, \"EMA Fast\", color=color.new(color.orange, 40), linewidth=1)\nplot(emaSlow, \"EMA Slow\", color=color.new(color.blue,   40), linewidth=1)\nplot(emaBias, \"EMA Bias\", color=color.new(color.white,  60), linewidth=2)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  LIQUIDITY SWEEP DETECTION\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\npivH = ta.pivothigh(high, i_pivLen, i_pivLen)\npivL = ta.pivotlow (low,  i_pivLen, i_pivLen)\n\nvar float rPivH = na\nvar float rPivL = na\nif not na(pivH)\n    rPivH := pivH\nif not na(pivL)\n    rPivL := pivL\n\nbullSwNow = inKZ and not na(rPivL) and low  < rPivL * (1 - i_sweepBuf / 100) and close > rPivL\nbearSwNow = inKZ and not na(rPivH) and high > rPivH * (1 + i_sweepBuf / 100) and close < rPivH\n\nvar int bullSwAge = 999\nvar int bearSwAge = 999\nif bullSwNow\n    bullSwAge := 0\nelse\n    bullSwAge := math.min(bullSwAge + 1, 999)\nif bearSwNow\n    bearSwAge := 0\nelse\n    bearSwAge := math.min(bearSwAge + 1, 999)\n\nbullSwReady = bullSwAge <= i_sweepWin\nbearSwReady = bearSwAge <= i_sweepWin\n\nplotshape(i_showSwMk and bullSwNow, title=\"Bull Sweep\",\n     style=shape.diamond, location=location.belowbar,\n     color=color.new(i_bullCol, 10), size=size.small)\nplotshape(i_showSwMk and bearSwNow, title=\"Bear Sweep\",\n     style=shape.diamond, location=location.abovebar,\n     color=color.new(i_bearCol, 10), size=size.small)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  FVG DETECTION  (3-candle imbalance)\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// Bullish FVG: price shot UP \u2192 gap between high[2] and low[0]\n// Bearish FVG: price shot DOWN \u2192 gap between low[2] and high[0]\n\nminGapSize = close * i_minGap / 100\n\nrawBullFVG = high[2] < low[0]  and (low[0]  - high[2]) >= minGapSize\nrawBearFVG = low[2]  > high[0] and (low[2]  - high[0]) >= minGapSize\n\n// Gap zone boundaries\nbFVGTop = low[0]    // top of bullish FVG\nbFVGBot = high[2]   // bot of bullish FVG\nrFVGTop = low[2]    // top of bearish FVG\nrFVGBot = high[0]   // bot of bearish FVG\n\n// Optional: require current price to retrace into FVG zone (confirmation)\nbullFVGRetrace = i_fvgRetrace ? (close <= bFVGTop and close >= bFVGBot) : true\nbearFVGRetrace = i_fvgRetrace ? (close >= rFVGBot and close <= rFVGTop) : true\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  ORDER BLOCK DETECTION\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// Bullish OB: last bearish candle before a significant UP move\n// Bearish OB: last bullish candle before a significant DOWN move\n\nbullOBHigh = ta.highest(high, i_obLookback)\nbullOBLow  = ta.lowest (low,  i_obLookback)\n\n// Bullish OB = last down-close candle in a swing low area\nvar float bOBTop = na\nvar float bOBBot = na\nvar float rOBTop = na\nvar float rOBBot = na\n\n// Detect bullish OB: bearish candle followed by a strong upward move\nbullOBCandle = close[1] < open[1]  // bearish bar\nbullOBImpulse = close > close[1] * 1.002  // strong follow-through up\nif bullOBCandle and bullOBImpulse\n    bOBTop := high[1]\n    bOBBot := low[1]\n\n// Detect bearish OB: bullish candle followed by a strong downward move\nbearOBCandle  = close[1] > open[1]  // bullish bar\nbearOBImpulse = close < close[1] * 0.998  // strong follow-through down\nif bearOBCandle and bearOBImpulse\n    rOBTop := high[1]\n    rOBBot := low[1]\n\n// OB confluence: price is touching / inside the OB zone\nbullOBTouch = not na(bOBTop) and close >= bOBBot and close <= bOBTop\nbearOBTouch = not na(rOBTop) and close >= rOBBot and close <= rOBTop\n\nbullOBPass = i_useOB ? bullOBTouch : true\nbearOBPass = i_useOB ? bearOBTouch : true\n\n// Draw OB boxes\nvar box obBullBox = na\nvar box obBearBox = na\n\nif bullOBCandle and bullOBImpulse and i_showOB\n    obBullBox := box.new(bar_index - 1, bOBTop, bar_index + i_extBars, bOBBot,\n         border_color=color.new(i_obCol, 40),\n         bgcolor=color.new(i_obCol, 88))\n\nif bearOBCandle and bearOBImpulse and i_showOB\n    obBearBox := box.new(bar_index - 1, rOBTop, bar_index + i_extBars, rOBBot,\n         border_color=color.new(i_obCol, 40),\n         bgcolor=color.new(i_obCol, 88))\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  FINAL SIGNAL\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// Long:  Kill Zone  +  Bull Sweep  +  Bullish FVG  +  OB  +  Trend\n// Short: Kill Zone  +  Bear Sweep  +  Bearish FVG  +  OB  +  Trend\n\ntrendPassBull = i_useTrend ? (trendUp and bullBias) : true\ntrendPassBear = i_useTrend ? (trendDn and bearBias) : true\n\nbullSig = rawBullFVG and bullSwReady and inKZ and bullFVGRetrace and bullOBPass and trendPassBull\nbullSig := bullSig and (i_dir == \"Both\" or i_dir == \"Long Only\")\n\nbearSig = rawBearFVG and bearSwReady and inKZ and bearFVGRetrace and bearOBPass and trendPassBear\nbearSig := bearSig and (i_dir == \"Both\" or i_dir == \"Short Only\")\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  ENTRY / SL / TP LEVELS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n// \u2500\u2500 Long \u2500\u2500\nbullEntry = i_entryMode == \"FVG Mid\"  ? (bFVGTop + bFVGBot) / 2\n          : i_entryMode == \"FVG Edge\" ? bFVGBot\n          : close\n\nbullSL = i_slMode == \"OB Edge\"    ? (not na(bOBBot) ? bOBBot * (1 - i_slBuf / 100) : bFVGBot * (1 - i_slBuf / 100))\n       : i_slMode == \"Gap Edge\"   ? bFVGBot * (1 - i_slBuf / 100)\n       : i_slMode == \"Pivot\"      ? (not na(rPivL)  ? rPivL  * (1 - i_slBuf / 100) : bFVGBot * (1 - i_slBuf / 100))\n       : ta.lowest(low, i_slLkb)  * (1 - i_slBuf / 100)\n\nbullRisk = math.max(math.abs(bullEntry - bullSL), syminfo.mintick)\nbullTP1  = bullEntry + bullRisk * i_tp1\nbullTP2  = bullEntry + bullRisk * i_tp2\n\n// \u2500\u2500 Short \u2500\u2500\nbearEntry = i_entryMode == \"FVG Mid\"  ? (rFVGTop + rFVGBot) / 2\n          : i_entryMode == \"FVG Edge\" ? rFVGTop\n          : close\n\nbearSL = i_slMode == \"OB Edge\"    ? (not na(rOBTop) ? rOBTop * (1 + i_slBuf / 100) : rFVGTop * (1 + i_slBuf / 100))\n       : i_slMode == \"Gap Edge\"   ? rFVGTop * (1 + i_slBuf / 100)\n       : i_slMode == \"Pivot\"      ? (not na(rPivH)  ? rPivH  * (1 + i_slBuf / 100) : rFVGTop * (1 + i_slBuf / 100))\n       : ta.highest(high, i_slLkb) * (1 + i_slBuf / 100)\n\nbearRisk = math.max(math.abs(bearSL - bearEntry), syminfo.mintick)\nbearTP1  = bearEntry - bearRisk * i_tp1\nbearTP2  = bearEntry - bearRisk * i_tp2\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  PLOTSHAPES \u2014 signal arrows (above/below bar)\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nplotshape(bullSig, title=\"Long Signal\",\n     style=shape.triangleup, location=location.belowbar,\n     color=i_bullCol, size=size.large)\n\nplotshape(bearSig, title=\"Short Signal\",\n     style=shape.triangledown, location=location.abovebar,\n     color=i_bearCol, size=size.large)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  ENTRY SHAPE  \u2014  plotshape at exact entry price\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// plotshape with location.absolute stamps a shape\n// AT the actual price level (not above/below bar).\n\nplotshape(bullSig ? bullEntry : na,\n     title=\"Long Entry Marker\",\n     location=location.absolute,\n     style=shape.circle,\n     color=color.white,\n     size=size.small)\n\nplotshape(bearSig ? bearEntry : na,\n     title=\"Short Entry Marker\",\n     location=location.absolute,\n     style=shape.circle,\n     color=color.white,\n     size=size.small)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  R:R SHAPE  \u2014  plot() dots at SL / TP1 / TP2\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// plot() with style_circles draws a visible dot at\n// the exact price level on the signal bar.\n\n// \u2500\u2500 Long R:R dots \u2500\u2500\nplot(bullSig ? bullSL   : na, \"Long SL Dot\",\n     style=plot.style_circles,\n     color=i_bearCol,\n     linewidth=5)\nplot(bullSig ? bullTP1  : na, \"Long TP1 Dot\",\n     style=plot.style_circles,\n     color=i_bullCol,\n     linewidth=5)\nplot(bullSig ? bullTP2  : na, \"Long TP2 Dot\",\n     style=plot.style_circles,\n     color=color.new(i_bullCol, 35),\n     linewidth=4)\nplot(bullSig ? bullEntry : na, \"Long Entry Dot\",\n     style=plot.style_circles,\n     color=color.white,\n     linewidth=6)\n\n// \u2500\u2500 Short R:R dots \u2500\u2500\nplot(bearSig ? bearSL   : na, \"Short SL Dot\",\n     style=plot.style_circles,\n     color=i_bearCol,\n     linewidth=5)\nplot(bearSig ? bearTP1  : na, \"Short TP1 Dot\",\n     style=plot.style_circles,\n     color=i_bullCol,\n     linewidth=5)\nplot(bearSig ? bearTP2  : na, \"Short TP2 Dot\",\n     style=plot.style_circles,\n     color=color.new(i_bullCol, 35),\n     linewidth=4)\nplot(bearSig ? bearEntry : na, \"Short Entry Dot\",\n     style=plot.style_circles,\n     color=color.white,\n     linewidth=6)\n\n// \u2500\u2500 Connecting lines: Entry \u2192 SL and Entry \u2192 TP1 on signal bar \u2500\u2500\n// These draw a vertical bracket on the chart at signal bar\nplot(bullSig ? bullEntry : na, \"Bull Entry Line\",\n     style=plot.style_linebr,\n     color=color.new(color.white, 50),\n     linewidth=1)\nplot(bearSig ? bearEntry : na, \"Bear Entry Line\",\n     style=plot.style_linebr,\n     color=color.new(color.white, 50),\n     linewidth=1)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  DRAW  \u2014  R:R PANEL + ENTRY SHAPE + TRADE CARD\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// Visual layers per signal:\n//  1. FVG gap zone (shaded band on chart)\n//  2. Wide R:R zone boxes (SL / TP1 / TP2) extending right\n//  3. Narrow vertical PANEL boxes on signal bar (proportional RR shape)\n//  4. Horizontal tick marks at Entry, SL, TP1, TP2\n//  5. Vertical spine line from SL \u2192 TP2\n//  6. Entry arrow label AT the entry price on signal bar\n//  7. Single combined trade-card label on the right\n\n// \u2500\u2500 Persistent drawing objects \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nvar box   bxFVG   = na\nvar box   bxSL    = na,  var box bxTP1   = na,  var box bxTP2   = na\nvar box   panRisk = na,  var box panTP1  = na,   var box panTP2  = na\nvar line  lnSpine = na\nvar line  lnTickE = na,  var line lnTickS = na\nvar line  lnTickT1= na,  var line lnTickT2= na\nvar line  lnEnt   = na,  var line lnSL   = na\nvar line  lnTP1   = na,  var line lnTP2  = na\nvar label lbArrow = na\nvar label lbCard  = na\n\nvar string lastSig  = \"\u2014\"\nvar int    sigCount = 0\nvar string lastKZ   = \"\u2014\"\n\n// \u2500\u2500 helper: format price to readable string \u2500\u2500\u2500\u2500\nf_price(p) => str.tostring(math.round(p, syminfo.mintick > 0.01 ? 2 : 5))\n\n// \u2500\u2500 LONG \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nif bullSig\n    sigCount += 1\n    lastSig  := \"Long\"\n    lastKZ   := inLondon ? \"London\" : inNY ? \"New York\" : \"Asia\"\n    R   = bar_index + i_extBars\n    B   = bar_index          // signal bar index\n    P   = B - 1              // panel left edge (1 bar before signal, keeps it tight)\n    riskPts = math.round(bullRisk, syminfo.mintick > 0.01 ? 2 : 5)\n\n    // \u2460 FVG zone (wide)\n    if i_showFVG\n        bxFVG := box.new(B - 2, bFVGTop, R, bFVGBot,\n             border_color=color.new(i_bullCol, 50), bgcolor=color.new(i_bullCol, 78))\n\n    // \u2461 Wide R:R zone boxes (extends right \u2014 gives context)\n    bxSL  := box.new(B, bullEntry, R, bullSL,\n         border_color=color.new(i_bearCol, 30), bgcolor=color.new(i_bearCol, i_alpha))\n    bxTP1 := box.new(B, bullTP1,   R, bullEntry,\n         border_color=color.new(i_bullCol, 30), bgcolor=color.new(i_bullCol, i_alpha))\n    bxTP2 := box.new(B, bullTP2,   R, bullTP1,\n         border_color=color.new(i_bullCol, 55),\n         bgcolor=color.new(i_bullCol, math.min(i_alpha + 10, 99)))\n\n    // \u2462 Narrow PANEL boxes on signal bar (proportional RR shape \u2014 2 bars wide)\n    panRisk := box.new(P, bullEntry, B + 1, bullSL,\n         border_color=color.new(i_bearCol, 10), bgcolor=color.new(i_bearCol, 45),\n         border_width=2)\n    panTP1  := box.new(P, bullTP1,   B + 1, bullEntry,\n         border_color=color.new(i_bullCol, 10), bgcolor=color.new(i_bullCol, 45),\n         border_width=2)\n    panTP2  := box.new(P, bullTP2,   B + 1, bullTP1,\n         border_color=color.new(i_bullCol, 30), bgcolor=color.new(i_bullCol, 62),\n         border_width=1)\n\n    // \u2463 Vertical spine  SL \u2192 TP2  (center of panel)\n    lnSpine := line.new(B, bullTP2, B, bullSL,\n         color=color.new(color.white, 55), width=1, style=line.style_solid)\n\n    // \u2464  ENTRY LINE \u2014 thick solid white, most prominent element on chart\n    lnEnt := line.new(B, bullEntry, R, bullEntry,\n         color=color.white, width=3, style=line.style_solid)\n\n    // Left-side label directly ON the entry line \u2014 price clearly printed\n    lbArrow := label.new(B, bullEntry,\n         \"\ud83c\udfaf BUY @ \" + f_price(bullEntry),\n         xloc      = xloc.bar_index,\n         style     = label.style_label_right,\n         color     = i_bullCol,\n         textcolor = color.white,\n         size      = size.normal)\n\n    // SL line \u2014 thick red, solid, labels on left\n    lnSL := line.new(B, bullSL, R, bullSL,\n         color=i_bearCol, width=2, style=line.style_solid)\n    lnTickS := line.new(B, bullSL, B, bullSL,    // dummy (reuse var)\n         color=na, width=1, style=line.style_solid)\n    label.new(B, bullSL,\n         \"\u2715 SL @ \" + f_price(bullSL),\n         xloc      = xloc.bar_index,\n         style     = label.style_label_right,\n         color     = color.new(i_bearCol, 20),\n         textcolor = color.white,\n         size      = size.small)\n\n    // TP1 line \u2014 solid green with label\n    lnTP1 := line.new(B, bullTP1, R, bullTP1,\n         color=i_bullCol, width=2, style=line.style_solid)\n    lnTickT1 := line.new(B, bullTP1, B, bullTP1, // dummy\n         color=na, width=1, style=line.style_solid)\n    label.new(B, bullTP1,\n         \"\u2714 TP1 \" + str.tostring(i_tp1) + \"R  @ \" + f_price(bullTP1),\n         xloc      = xloc.bar_index,\n         style     = label.style_label_right,\n         color     = color.new(i_bullCol, 20),\n         textcolor = color.white,\n         size      = size.small)\n\n    // TP2 line \u2014 dashed green with label\n    lnTP2 := line.new(B, bullTP2, R, bullTP2,\n         color=color.new(i_bullCol, 30), width=1, style=line.style_dashed)\n    lnTickT2 := line.new(B, bullTP2, B, bullTP2, // dummy\n         color=na, width=1, style=line.style_solid)\n    label.new(B, bullTP2,\n         \"\u2714 TP2 \" + str.tostring(i_tp2) + \"R  @ \" + f_price(bullTP2),\n         xloc      = xloc.bar_index,\n         style     = label.style_label_right,\n         color     = color.new(i_bullCol, 45),\n         textcolor = color.white,\n         size      = size.small)\n\n    // \u2466 Right-side trade card (risk summary)\n    if i_showLabels\n        lbCard := label.new(R, (bullTP1 + bullEntry) / 2,\n             \"LONG  |  Risk: \" + str.tostring(riskPts) + \" pts  |  TP1: \" + str.tostring(i_tp1) + \"R  TP2: \" + str.tostring(i_tp2) + \"R\",\n             xloc      = xloc.bar_index,\n             style     = label.style_label_left,\n             color     = color.new(i_bullCol, 25),\n             textcolor = color.white,\n             size      = size.small)\n\n// \u2500\u2500 SHORT \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nif bearSig\n    sigCount += 1\n    lastSig  := \"Short\"\n    lastKZ   := inLondon ? \"London\" : inNY ? \"New York\" : \"Asia\"\n    R   = bar_index + i_extBars\n    B   = bar_index\n    P   = B - 1\n    riskPts = math.round(bearRisk, syminfo.mintick > 0.01 ? 2 : 5)\n\n    // \u2460 FVG zone\n    if i_showFVG\n        bxFVG := box.new(B - 2, rFVGTop, R, rFVGBot,\n             border_color=color.new(i_bearCol, 50), bgcolor=color.new(i_bearCol, 78))\n\n    // \u2461 Wide R:R zone boxes\n    bxSL  := box.new(B, bearSL,    R, bearEntry,\n         border_color=color.new(i_bearCol, 30), bgcolor=color.new(i_bearCol, i_alpha))\n    bxTP1 := box.new(B, bearEntry, R, bearTP1,\n         border_color=color.new(i_bullCol, 30), bgcolor=color.new(i_bullCol, i_alpha))\n    bxTP2 := box.new(B, bearTP1,   R, bearTP2,\n         border_color=color.new(i_bullCol, 55),\n         bgcolor=color.new(i_bullCol, math.min(i_alpha + 10, 99)))\n\n    // \u2462 Narrow PANEL boxes on signal bar\n    panRisk := box.new(P, bearSL,    B + 1, bearEntry,\n         border_color=color.new(i_bearCol, 10), bgcolor=color.new(i_bearCol, 45),\n         border_width=2)\n    panTP1  := box.new(P, bearEntry, B + 1, bearTP1,\n         border_color=color.new(i_bullCol, 10), bgcolor=color.new(i_bullCol, 45),\n         border_width=2)\n    panTP2  := box.new(P, bearTP1,   B + 1, bearTP2,\n         border_color=color.new(i_bullCol, 30), bgcolor=color.new(i_bullCol, 62),\n         border_width=1)\n\n    // \u2463 Vertical spine  TP2 \u2192 SL\n    lnSpine := line.new(B, bearSL, B, bearTP2,\n         color=color.new(color.white, 55), width=1, style=line.style_solid)\n\n    // \u2464  ENTRY LINE \u2014 thick solid white, most prominent element on chart\n    lnEnt := line.new(B, bearEntry, R, bearEntry,\n         color=color.white, width=3, style=line.style_solid)\n\n    // Left-side label directly ON the entry line \u2014 price clearly printed\n    lbArrow := label.new(B, bearEntry,\n         \"\ud83c\udfaf SELL @ \" + f_price(bearEntry),\n         xloc      = xloc.bar_index,\n         style     = label.style_label_right,\n         color     = i_bearCol,\n         textcolor = color.white,\n         size      = size.normal)\n\n    // SL line \u2014 thick red, solid, label on left\n    lnSL := line.new(B, bearSL, R, bearSL,\n         color=i_bearCol, width=2, style=line.style_solid)\n    lnTickS := line.new(B, bearSL, B, bearSL,\n         color=na, width=1, style=line.style_solid)\n    label.new(B, bearSL,\n         \"\u2715 SL @ \" + f_price(bearSL),\n         xloc      = xloc.bar_index,\n         style     = label.style_label_right,\n         color     = color.new(i_bearCol, 20),\n         textcolor = color.white,\n         size      = size.small)\n\n    // TP1 line \u2014 solid green with label\n    lnTP1 := line.new(B, bearTP1, R, bearTP1,\n         color=i_bullCol, width=2, style=line.style_solid)\n    lnTickT1 := line.new(B, bearTP1, B, bearTP1,\n         color=na, width=1, style=line.style_solid)\n    label.new(B, bearTP1,\n         \"\u2714 TP1 \" + str.tostring(i_tp1) + \"R  @ \" + f_price(bearTP1),\n         xloc      = xloc.bar_index,\n         style     = label.style_label_right,\n         color     = color.new(i_bullCol, 20),\n         textcolor = color.white,\n         size      = size.small)\n\n    // TP2 line \u2014 dashed green with label\n    lnTP2 := line.new(B, bearTP2, R, bearTP2,\n         color=color.new(i_bullCol, 30), width=1, style=line.style_dashed)\n    lnTickT2 := line.new(B, bearTP2, B, bearTP2,\n         color=na, width=1, style=line.style_solid)\n    label.new(B, bearTP2,\n         \"\u2714 TP2 \" + str.tostring(i_tp2) + \"R  @ \" + f_price(bearTP2),\n         xloc      = xloc.bar_index,\n         style     = label.style_label_right,\n         color     = color.new(i_bullCol, 45),\n         textcolor = color.white,\n         size      = size.small)\n\n    // \u2466 Right-side trade card (risk summary)\n    if i_showLabels\n        lbCard := label.new(R, (bearEntry + bearTP1) / 2,\n             \"SHORT  |  Risk: \" + str.tostring(riskPts) + \" pts  |  TP1: \" + str.tostring(i_tp1) + \"R  TP2: \" + str.tostring(i_tp2) + \"R\",\n             xloc      = xloc.bar_index,\n             style     = label.style_label_left,\n             color     = color.new(i_bearCol, 25),\n             textcolor = color.white,\n             size      = size.small)\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  MOMENTUM BAR COLORING\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// Color bars green/red based on EMA cross momentum when inside a KZ\n\nbarMomBull = trendUp and inKZ and bullBias\nbarMomBear = trendDn and inKZ and bearBias\nbarcolor(barMomBull ? color.new(i_bullCol, 65) : barMomBear ? color.new(i_bearCol, 65) : na,\n     title=\"Momentum Bar Color\")\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  DASHBOARD\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nvar table dash = table.new(position.top_right, 2, 12,\n     border_width=1,\n     border_color=color.new(color.gray, 55),\n     bgcolor=color.new(#0d1117, 10))\n\nif i_showDash and barstate.islast\n\n    // Header\n    kzActive  = inLondon ? \"LONDON  KZ\" : inNY ? \"NEW YORK  KZ\" : inAsiaKZ ? \"ASIA  KZ\" : \"NO KILL ZONE\"\n    kzHdrCol  = inLondon ? color.new(#1565c0, 15) : inNY ? color.new(#1b5e20, 15) : inAsiaKZ ? color.new(#4a148c, 15) : color.new(#37474f, 40)\n    table.cell(dash, 0, 0, \"SCALP PRO\",  text_color=color.white, bgcolor=kzHdrCol, text_size=size.normal, text_halign=text.align_center)\n    table.cell(dash, 1, 0, kzActive,     text_color=color.white, bgcolor=kzHdrCol, text_size=size.normal, text_halign=text.align_center)\n\n    // Kill zone clock\n    utcStr = \"UTC \" + str.tostring(utcH) + \"h\"\n    table.cell(dash, 0, 1, \"UTC Clock\",    text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 1, utcStr,         text_color=color.white, bgcolor=color.new(color.gray, 50))\n\n    // Sessions enabled\n    sesStr = (i_useLondon ? \"LON \" : \"\") + (i_useNY ? \"NY \" : \"\") + (i_useAsia ? \"ASIA\" : \"\")\n    table.cell(dash, 0, 2, \"Sessions\",     text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 2, sesStr,         text_color=color.white, bgcolor=color.new(color.gray, 55))\n\n    // Bias (EMA 200)\n    biasLbl = bullBias ? \"Bullish\" : bearBias ? \"Bearish\" : \"Neutral\"\n    biasCol = bullBias ? color.new(#00e676, 25) : bearBias ? color.new(#ff1744, 25) : color.new(color.gray, 25)\n    table.cell(dash, 0, 3, \"Bias (EMA \" + str.tostring(i_ema200) + \")\", text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 3,  biasLbl,      text_color=color.white, bgcolor=biasCol)\n\n    // Trend\n    trendLbl = trendUp ? \"Up  (Fast>Slow)\" : trendDn ? \"Down (Fast<Slow)\" : \"Ranging\"\n    trendCol = trendUp ? color.new(#00e676, 35) : trendDn ? color.new(#ff1744, 35) : color.new(color.gray, 35)\n    table.cell(dash, 0, 4, \"Trend\",        text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 4, trendLbl,       text_color=color.white, bgcolor=trendCol)\n\n    // Bull sweep\n    bSwL = bullSwNow ? \"SWEPT  now\" : bullSwReady ? \"Ready  \" + str.tostring(bullSwAge) + \"b ago\" : \"Waiting\"\n    bSwC = bullSwNow ? color.new(#00e676, 5)  : bullSwReady ? color.new(color.orange, 25) : color.new(color.gray, 55)\n    table.cell(dash, 0, 5, \"Bull Sweep\",   text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 5, bSwL,           text_color=color.white, bgcolor=bSwC)\n\n    // Bear sweep\n    rSwL = bearSwNow ? \"SWEPT  now\" : bearSwReady ? \"Ready  \" + str.tostring(bearSwAge) + \"b ago\" : \"Waiting\"\n    rSwC = bearSwNow ? color.new(#ff1744, 5) : bearSwReady ? color.new(color.orange, 25) : color.new(color.gray, 55)\n    table.cell(dash, 0, 6, \"Bear Sweep\",   text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 6, rSwL,           text_color=color.white, bgcolor=rSwC)\n\n    // FVG detected\n    fvgLbl = rawBullFVG ? \"Bullish FVG\" : rawBearFVG ? \"Bearish FVG\" : \"None\"\n    fvgCol = rawBullFVG ? color.new(#00e676, 40) : rawBearFVG ? color.new(#ff1744, 40) : color.new(color.gray, 55)\n    table.cell(dash, 0, 7, \"FVG\",          text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 7, fvgLbl,         text_color=color.white, bgcolor=fvgCol)\n\n    // OB confluence\n    obLbl = bullOBTouch ? \"Bull OB  \u2713\" : bearOBTouch ? \"Bear OB  \u2713\" : \"None\"\n    obCol = bullOBTouch ? color.new(#00e676, 40) : bearOBTouch ? color.new(#ff1744, 40) : color.new(color.gray, 55)\n    table.cell(dash, 0, 8, \"Order Block\",  text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 8, obLbl,          text_color=color.white, bgcolor=obCol)\n\n    // Last Signal\n    sigCol = lastSig == \"Long\" ? color.new(#00e676, 25) : lastSig == \"Short\" ? color.new(#ff1744, 25) : color.new(color.gray, 50)\n    table.cell(dash, 0, 9,  \"Last Signal\", text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 9,  lastSig + (lastKZ != \"\u2014\" ? \"  [\" + lastKZ + \"]\" : \"\"),\n         text_color=color.white, bgcolor=sigCol)\n\n    // R:R\n    table.cell(dash, 0, 10, \"R:R  TP1/TP2\", text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 10, str.tostring(i_tp1) + \"R  /  \" + str.tostring(i_tp2) + \"R\",\n         text_color=color.white, bgcolor=color.new(color.gray, 50))\n\n    // Total signals\n    table.cell(dash, 0, 11, \"Total Signals\", text_color=color.white, bgcolor=color.new(color.gray, 70))\n    table.cell(dash, 1, 11, str.tostring(sigCount),\n         text_color=color.white, bgcolor=color.new(color.gray, 50))\n\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n// \u2591\u2591  ALERTS\n// \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\nalertcondition(bullSig, title=\"Scalp Long Signal\",\n     message=\"SCALP LONG on {{ticker}} @ {{close}} | KZ + Sweep + FVG + OB aligned.\")\nalertcondition(bearSig, title=\"Scalp Short Signal\",\n     message=\"SCALP SHORT on {{ticker}} @ {{close}} | KZ + Sweep + FVG + OB aligned.\")\nalertcondition(bullSig or bearSig, title=\"Scalp Signal (Any)\",\n     message=\"SCALP Signal on {{ticker}} @ {{close}} | Full confluence detected.\")\nalertcondition(bullSwNow, title=\"Bull Liquidity Sweep\",\n     message=\"BULL SWEEP on {{ticker}} @ {{close}} | Pivot low swept, watching for FVG.\")\nalertcondition(bearSwNow, title=\"Bear Liquidity Sweep\",\n     message=\"BEAR SWEEP on {{ticker}} @ {{close}} | Pivot high swept, watching for FVG.\")\nalertcondition(inLondon and not inLondon[1], title=\"London KZ Open\",\n     message=\"LONDON KILL ZONE opened on {{ticker}}.\")\nalertcondition(inNY and not inNY[1], title=\"New York KZ Open\",\n     message=\"NEW YORK KILL ZONE opened on {{ticker}}.\")\n"
  }
];